	  {
	  EXTI_ClearITPendingBit(EXTI_Line10);  //ïŋ―ïŋ―ïŋ―LINE10ïŋ―Ïĩïŋ―ïŋ―ÐķÏąïŋ―ÖūÎŧ

	  }
	if(EXTI_GetITStatus(EXTI_Line11)!=RESET)
