	  }
	if(EXTI_GetITStatus(EXTI_Line12)!=RESET)
	  {
			sys_flag.Interrupt_Alive = OK; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐķÏīïŋ―ïŋ―ïŋ―

			Switch_Inf.OpenWait_7ms = 0;

			Switch_Inf.CloseWait_3ms = 0;


	  		 if(Switch_Inf.air_on_flag)
	  		 	{
	  		 		if(Switch_Inf.OpenWait_7ms >= 7)
	  		 			{

	  		 			}

RELAY6_ON;  //ïŋ―Í·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―


	  		 	}
			 else
			 	{
			 		if(Switch_Inf.CloseWait_3ms >= 3)
			 			{


			 			}
					RELAY6_OFF;  //ïŋ―Í·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―


			 	}

			 if(Switch_Inf.gas_on_flag)
			 	{
			 		RELAY7_ON;
			 	}
			 else
			 	{
			 		RELAY7_OFF;
			 	}

			 if(Switch_Inf.dian_huo_flag)
			 	{
			 		RELAY8_ON;
			 	}
			 else
			 	{
			 		RELAY8_OFF;
			 	}


			 if(Switch_Inf.water_switch_flag )
			 	{

			 		RELAY5_ON;
			 	}
			 else
			 	{
			 		RELAY5_OFF;

			 	}

			 if(Switch_Inf.Water_Valve_Flag)
			 	{
			 		RELAY4_ON;
			 	}
			 else
			 	{
			 		RELAY4_OFF;
			 	}

			 if(Switch_Inf.pai_wu_flag)
			 	{
			 		RELAY9_ON;
			 	}
			 else
			 	{
			 		RELAY9_OFF;
			 	}

			 if(Switch_Inf.MingHuo_Flag)
			 	{
			 		RELAY2_ON;
			 	}
			 else
			 	{
			 		RELAY2_OFF;
			 	}

			  if(Switch_Inf.LianXu_PaiWu_flag)
			 	{
			 		RELAY10_ON;
			 	}
			 else
			 	{
			 		RELAY10_OFF;
			 	}


	 	 EXTI_ClearITPendingBit(EXTI_Line12);  //ïŋ―ïŋ―ïŋ―LINE12ïŋ―Ïĩïŋ―ïŋ―ÐķÏąïŋ―ÖūÎŧ

	  }
	if(EXTI_GetITStatus(EXTI_Line13)!=RESET)
	  {
	  EXTI_ClearITPendingBit(EXTI_Line13);  //ïŋ―ïŋ―ïŋ―LINE13ïŋ―Ïĩïŋ―ïŋ―ÐķÏąïŋ―ÖūÎŧ

	  }
	if(EXTI_GetITStatus(EXTI_Line14)!=RESET)
