	  }
 	if(EXTI_GetITStatus(EXTI_Line15)!=RESET)
	  {
	  EXTI_ClearITPendingBit(EXTI_Line15);  //ïŋ―ïŋ―ïŋ―LINE15ïŋ―Ïĩïŋ―ïŋ―ÐķÏąïŋ―ÖūÎŧ

