}



/**
  * @brief  This function handles RTC interrupt request.
  * @param  None
  * @retval None
  */
void RTC_IRQHandler(void)
{
	  if (RTC_GetITStatus(RTC_IT_SEC) != RESET)
	  {
	    /* Clear the RTC Second interrupt */
	    RTC_ClearITPendingBit(RTC_IT_SEC);

	    /* Enable time update */
	    TimeDisplay = 1;



	    /* Wait until last write operation on RTC registers has finished */
	    RTC_WaitForLastTask();
	  }
}

void USART1_IRQHandler(void)
{

  uint8 Res = 0;

  if(USART_GetITStatus(USART1, USART_IT_RXNE) != RESET)  //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
	{
		USART_ClearITPendingBit(USART1,USART_IT_RXNE); //ïŋ―ïŋ―ïŋ―ïŋ―ÐķÏąïŋ―Öū
		Res =USART_ReceiveData(USART1);//(USART2->DR);	//ïŋ―ïŋ―ČĄïŋ―ïŋ―ïŋ―Õĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
		if(U1_Inf.Rx_temp_length == 0&&U1_Inf.Recive_Ok_Flag == 0)
		  {
		  	U1_Inf.RX_Data[0]=Res;
		  	U1_Inf.Rx_temp_length++;
		  	U1_Inf.Recive_Flag=1;
		  	U1_Inf.Recive_Time=0;
		  }
  		else if(U1_Inf.Rx_temp_length > 0 && U1_Inf.Recive_Ok_Flag == 0)
		  {		if(U1_Inf.Rx_temp_length > 250)
		  			U1_Inf.Rx_temp_length = 0;
				U1_Inf.RX_Data[U1_Inf.Rx_temp_length]=Res;
				U1_Inf.Rx_temp_length++;
				U1_Inf.Recive_Time=0;
		  }
	}

  if(USART_GetFlagStatus(USART1, USART_FLAG_ORE) == SET)//ïŋ―ïŋ―ïŋ―OREïŋ―ïŋ―Öū
  	{
  		USART_ClearFlag(USART1,USART_FLAG_ORE);
		USART_ReceiveData(USART1);
  	}

  	if (USART_GetFlagStatus(USART1, USART_FLAG_PE) != RESET)
    {

        USART_ReceiveData(USART1);
      USART_ClearFlag(USART1, USART_FLAG_PE);
    }

 	if (USART_GetFlagStatus(USART1, USART_FLAG_FE) != RESET)
    {

       USART_ReceiveData(USART1);
       USART_ClearFlag(USART1, USART_FLAG_FE);
    }
}




