void SysTick_Delay_us(uint32_t us)
{
	uint32_t i;
	SysTick_Config(72);

	for(i=0; i<us; i++)
	{
		while( !((SysTick->CTRL) & (1<<16)) );
	}

	SysTick->CTRL &= ~ SysTick_CTRL_ENABLE_Msk;
}

void SysTick_Delay_ms(uint32_t ms)
{
	uint32_t i;
	SysTick_Config(72000);

	for(i=0; i<ms; i++)
	{
		while( !((SysTick->CTRL) & (1<<16)) );
	}

	SysTick->CTRL &= ~ SysTick_CTRL_ENABLE_Msk;
}


void SysTick_Init(void)
{
        if(SysTick_Config(SystemCoreClock/1000))         //1msïŋ―ïŋ―Ęąïŋ―ïŋ―
        {
                while(1);
        }
       // SysTick->CTRL &= ~SysTick_CTRL_ENABLE_Msk;                         //ïŋ―ïŋ―ïŋ―Þ·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Øąïŋ―
}

