#ifndef __BSP_RCCCLKCONFIG_H
#define __BSP_RCCCLKCONFIG_H

#include "stm32f10x.h"

void HSE_SetSysClk( uint32_t RCC_PLLMul_x );
void MCO_GPIO_Config(void);
void HSI_SetSysClk( uint32_t RCC_PLLMul_x );
#endif /*__BSP_RCCCLKCONFIG_H */

#include "bsp_rccclkconfig.h"

void HSE_SetSysClk( uint32_t RCC_PLLMul_x )
{
	ErrorStatus HSEStatus;

	// ïŋ―ïŋ―RCC ïŋ―Äīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Îŧïŋ―Éļïŋ―ÎŧÖĩ
	RCC_DeInit();	

	// Ęđïŋ―ïŋ― HSE 
	RCC_HSEConfig(RCC_HSE_ON);

	HSEStatus = RCC_WaitForHSEStartUp();

	if( HSEStatus == SUCCESS )
	{
		// Ęđïŋ―ïŋ―ÔĪČĄÖļ
		FLASH_PrefetchBufferCmd(FLASH_PrefetchBuffer_Enable);
		FLASH_SetLatency(FLASH_Latency_2);

		RCC_HCLKConfig(RCC_SYSCLK_Div1);
		RCC_PCLK1Config(RCC_HCLK_Div2);
		RCC_PCLK2Config(RCC_HCLK_Div1);

		// ïŋ―ïŋ―ïŋ―ïŋ― PLLCLK = HSE * RCC_PLLMul_x
    RCC_PLLConfig(RCC_PLLSource_HSE_Div1, RCC_PLLMul_x);

    // Ęđïŋ―ïŋ―PLL
		RCC_PLLCmd(ENABLE);

		// ïŋ―Čīïŋ―PLLïŋ―Čķïŋ―
		while( RCC_GetFlagStatus(RCC_FLAG_PLLRDY) == RESET );

    // ŅĄïŋ―ïŋ―ÏĩÍģĘąïŋ―ïŋ―
		RCC_SYSCLKConfig(RCC_SYSCLKSource_PLLCLK);

    while( RCC_GetSYSCLKSource() != 0x08 );
	}
	else
  {
		/* ïŋ―ïŋ―ïŋ―HSE ïŋ―ïŋ―ïŋ―ïŋ―Ę§ïŋ―ÜĢïŋ―ïŋ―Ãŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Óīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äīïŋ―ïŋ―ïŋ― */
	}
}

void HSI_SetSysClk( uint32_t RCC_PLLMul_x )
{
	__IO uint32_t HSIStatus = 0;

	// ïŋ―ïŋ―RCC ïŋ―Äīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Îŧïŋ―Éļïŋ―ÎŧÖĩ
	RCC_DeInit();	

	// Ęđïŋ―ïŋ― HSI 
	RCC_HSICmd(ENABLE);

	HSIStatus = RCC->CR & RCC_CR_HSIRDY;

	if( HSIStatus == RCC_CR_HSIRDY )
	{
		// Ęđïŋ―ïŋ―ÔĪČĄÖļ
		FLASH_PrefetchBufferCmd(FLASH_PrefetchBuffer_Enable);
		FLASH_SetLatency(FLASH_Latency_2);

		RCC_HCLKConfig(RCC_SYSCLK_Div1);
		RCC_PCLK1Config(RCC_HCLK_Div2);
		RCC_PCLK2Config(RCC_HCLK_Div1);

		// ïŋ―ïŋ―ïŋ―ïŋ― PLLCLK = HSE * RCC_PLLMul_x
    RCC_PLLConfig(RCC_PLLSource_HSI_Div2, RCC_PLLMul_x);

    // Ęđïŋ―ïŋ―PLL
		RCC_PLLCmd(ENABLE);

		// ïŋ―Čīïŋ―PLLïŋ―Čķïŋ―
		while( RCC_GetFlagStatus(RCC_FLAG_PLLRDY) == RESET );

    // ŅĄïŋ―ïŋ―ÏĩÍģĘąïŋ―ïŋ―
		RCC_SYSCLKConfig(RCC_SYSCLKSource_PLLCLK);

    while( RCC_GetSYSCLKSource() != 0x08 );
	}
	else
  {
		/* ïŋ―ïŋ―ïŋ―HSI ïŋ―ïŋ―ïŋ―ïŋ―Ę§ïŋ―ÜĢïŋ―ïŋ―Ãŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Óīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äīïŋ―ïŋ―ïŋ― */
	}
}

void MCO_GPIO_Config()
{
	GPIO_InitTypeDef  GPIO_InitStruct;

	RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOA, ENABLE);

	GPIO_InitStruct.GPIO_Pin = GPIO_Pin_8;
	GPIO_InitStruct.GPIO_Mode = GPIO_Mode_AF_PP;
	GPIO_InitStruct.GPIO_Speed = GPIO_Speed_50MHz;

	GPIO_Init(GPIOA, &GPIO_InitStruct);	
}

