   //USART ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―

	USART_InitStructure.USART_BaudRate = bound;//Ōŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ9600;
	USART_InitStructure.USART_WordLength = USART_WordLength_8b;//ïŋ―Öģïŋ―ÎŠ8Îŧïŋ―ïŋ―ïŋ―Ýļïŋ―Ę―
	USART_InitStructure.USART_StopBits = USART_StopBits_1;//Ōŧïŋ―ïŋ―ÍĢÖđÎŧ
	USART_InitStructure.USART_Parity = USART_Parity_No;//ïŋ―ïŋ―ïŋ―ïŋ―ÅžÐĢïŋ―ïŋ―Îŧ
	USART_InitStructure.USART_HardwareFlowControl = USART_HardwareFlowControl_None;//ïŋ―ïŋ―Óēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	USART_InitStructure.USART_Mode = USART_Mode_Rx | USART_Mode_Tx;	//ïŋ―Õ·ïŋ―ÄĢĘ―

    USART_Init(USART1, &USART_InitStructure); //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    USART_ITConfig(USART1, USART_IT_RXNE, ENABLE);//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
    USART_Cmd(USART1, ENABLE);                    //Ęđïŋ―Üīïŋ―ïŋ―ïŋ― 

}

void u1_printf(char* fmt,...)  
{  
  	int len=0;
	int cnt=0;
	va_list ap;
	va_start(ap,fmt);
	vsprintf((char*)U1_Inf.TX_Data,fmt,ap);
	va_end(ap);
	len = strlen((const char*)U1_Inf.TX_Data);
	while(len--)
	  {
	  while(USART_GetFlagStatus(USART1,USART_FLAG_TC)!=1); //ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―Í―ïŋ―ïŋ―ïŋ―
	  USART_SendData(USART1,U1_Inf.TX_Data[cnt++]);
	  }
}


void Usart_SendByte( USART_TypeDef * pUSARTx, uint8_t ch )
{
	/* ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―Ýĩïŋ―USART1 */
	USART_SendData(pUSARTx,ch);

	/* ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	while (USART_GetFlagStatus(pUSARTx, USART_FLAG_TXE) == RESET);	
}
/*****************  Öļïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ČĩÄ·ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ― **********************/
void Usart_SendStr_length( USART_TypeDef * pUSARTx, uint8_t *str,uint32_t strlen )
{
	unsigned int k=0; 
    do 
    {
        Usart_SendByte( pUSARTx, *(str + k) );
        k++;
    } while(k < strlen);
}

/*****************  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ― **********************/
void Usart_SendString( USART_TypeDef * pUSARTx, uint8_t *str)
{
	unsigned int k=0;
    do 
    {
        Usart_SendByte( pUSARTx, *(str + k) );
        k++;
    } while(*(str + k)!='\0');
}



//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―ČĄïŋ―Úēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÏĒ
void ModBus_Communication(void)
{

		uint8  i = 0;	

		uint16 checksum = 0;
		uint16 Address = 0;


		if(U1_Inf.Recive_Ok_Flag)
			{
				U1_Inf.Recive_Ok_Flag = 0;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Åķ
				 //ïŋ―Øąïŋ―ïŋ―Ðķïŋ―
				USART_ITConfig(USART1, USART_IT_RXNE, DISABLE); 

				checksum  = U1_Inf.RX_Data[U1_Inf.RX_Length - 2] * 256 + U1_Inf.RX_Data[U1_Inf.RX_Length - 1];

			//ïŋ―Ï°ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―čąļïŋ―ïŋ―ïŋ―ÐšÅ―ïŋ―ïŋ―ïŋ―ïŋ―Þļïŋ―
				if(checksum == ModBusCRC16(U1_Inf.RX_Data,U1_Inf.RX_Length))
					{
						//ïŋ―ïŋ―ČĄïŋ―ïŋ―ïŋ―ØĩÄĩïŋ―Ö·ïŋ―ïŋ―ÏĒïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―Ũĩïŋ―Ö·ÎŠ254ïŋ―ïŋ―0x03Öļïŋ―ïŋ―   ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýĩïŋ―Ö·ÎŠ1000ïŋ―ïŋ―ÖŧŌŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ïŋ―Íŧïŋ―
						if(U1_Inf.RX_Data[0] == 254 && U1_Inf.RX_Data[1] == 0x03)
							{
								Address = U1_Inf.RX_Data[2] *256+ U1_Inf.RX_Data[3];
								if(Address == 1000)
									{
										U1_Inf.TX_Data[0] = U1_Inf.RX_Data[0];
										U1_Inf.TX_Data[1] = 0x03;// 
										U1_Inf.TX_Data[2] = 2; //ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ïŋ―ÎŠ2ïŋ―ïŋ― ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äąïŋ―***

										U1_Inf.TX_Data[3] = 0;
										U1_Inf.TX_Data[4] =  Sys_Admin.ModBus_Address;
										checksum  = ModBusCRC16(U1_Inf.TX_Data,7);   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―Äąïŋ―
										U1_Inf.TX_Data[5]  = checksum >> 8 ;
										U1_Inf.TX_Data[6]  = checksum & 0x00FF;
										Usart_SendStr_length(USART1,U1_Inf.TX_Data,7);

									}
							}

						Union_New_Server_Cmd_Analyse();



					}



			//ïŋ―Ô―ïŋ―ïŋ―Õŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
				for( i = 0; i < 100;i++ )
					U1_Inf.RX_Data[i] = 0x00;

			//ïŋ―ïŋ―ïŋ―Âŋïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
				USART_ITConfig(USART1, USART_IT_RXNE, ENABLE); 

			}
}








uint16 ModBusCRC16(unsigned char *ptr,uint8 size)
{
		uint16 a,b,temp;
		uint16 CRC16;
		uint16 checksum ;

		CRC16 = 0XFFFF;	

		for(a = 0; a < (size -2) ; a++ )
			{
				CRC16 = *ptr ^ CRC16;
				for(b = 0;b < 8;b++)
					{
						temp = CRC16 & 0X0001;
						CRC16 = CRC16 >> 1;
						if(temp)
							CRC16 = CRC16 ^ 0XA001;	
					}

				*ptr++;
			}

		checksum = ((CRC16 & 0x00FF) << 8) |((CRC16 & 0XFF00) >> 8);


		return checksum;
}

uint16 Lcd_CRC16(unsigned char *ptr,uint8 size)
{
		uint16 a,b,temp;
		uint16 CRC16;
		uint16 checksum ;

		CRC16 = 0XFFFF;	


		for(a = 0; a < size ; a++ )
			{
				CRC16 = *ptr ^ CRC16;
				for(b = 0;b < 8;b++)
					{
						temp = CRC16 & 0X0001;
						CRC16 = CRC16 >> 1;
						if(temp)
							CRC16 = CRC16 ^ 0XA001;	
					}

				*ptr++;
			}

		checksum = ((CRC16 & 0x00FF) << 8) |((CRC16 & 0XFF00) >> 8);


		return checksum;
}



