uint8 A1B1_Jizu_ReadResponse(uint8 address)
{
	uint8 Bytes = 0;
	uint8 index = 0;
	uint16 checksum = 0;
	Bytes = sizeof(JiZu[address].Datas);
	U1_Inf.TX_Data[0] = Sys_Admin.ModBus_Address;
	U1_Inf.TX_Data[1]= 0x03;
	U1_Inf.TX_Data[2] = Bytes; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ČļÄąïŋ―


	for(index = 3; index < (Bytes + 3); index = index + 2)
		{
			U1_Inf.TX_Data[index] = JiZu[address].Datas[index + 1 -3]; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ßĩÍķïŋ―Ņ­ïŋ―ïŋ―
			U1_Inf.TX_Data[index + 1] = JiZu[address].Datas[index -3]; 
		}


	checksum  = ModBusCRC16(U1_Inf.TX_Data,Bytes + 5);
	U1_Inf.TX_Data[Bytes + 3] = checksum >> 8;
	U1_Inf.TX_Data[Bytes + 4] = checksum & 0x00FF;
	Usart_SendStr_length(USART1,U1_Inf.TX_Data,Bytes +5);

		return 0;
}


uint8  Union_New_Server_Cmd_Analyse(void)
{
   uint8 Cmd = 0;
   uint8 index = 0;
   uint8 Length = 0;
   uint16 Value = 0;
   uint16 Address = 0;
   uint16 Data = 0; 
   uint8  Device_ID = 1; //ïŋ―ïŋ―ïŋ―Ýĩïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Üīïŋ― ************88
   float  value_buffer = 0;
   uint16 check_sum = 0;
   uint16 Data1 = 0;
   uint16 Data2 = 0;
   uint16 Data3 = 0;
   uint32 Data32_Buffer = 0;
   uint32 Int_CharH = 0;
   uint32 Int_CHarL = 0;
   uint8 Code[6] = {0};



	//Float_Int.value  ïŋ―ïŋ―ïŋ―Úĩïŋ―ïŋ―ïŋ―ïŋ―Čĩïŋ―ŨŠïŋ―ïŋ―


   Cmd = U1_Inf.RX_Data[1];
   Address = U1_Inf.RX_Data[2] *256+ U1_Inf.RX_Data[3];
   Length = U1_Inf.RX_Data[4] *256+ U1_Inf.RX_Data[5];
   Value = U1_Inf.RX_Data[4] *256+ U1_Inf.RX_Data[5];	//06ïŋ―ïŋ―Ę―ïŋ―ÂĢïŋ―value = length



   if(U1_Inf.RX_Data[0] >= 1)
	   {
		   //ïŋ―ïŋ―ïŋ―ïŋ―ŅŊïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―1Ęąïŋ―ïŋ―ïŋ―Ôķïŋ―ïŋ―Ðŧïŋ―ÎŠïŋ―Ô·ïŋ―ŅŊïŋ―ĘĩÄĩïŋ―Ö·

		   Device_ID = Sys_Admin.ModBus_Address;

		   if(U1_Inf.RX_Data[0] != Sys_Admin.ModBus_Address)
			   {
				   return 0;   //ïŋ―Įąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·Öąïŋ―ïŋ―ïŋ―Ëģïŋ―
			   }
	   }


   switch (Cmd)
	   {
		   case 03:  //00 03 01 F3 00 0F F5 D0	   

				   switch (Address)
					   {
						   case 0x00:
								   if(Length == 11)  //ïŋ―ïŋ―ßĩïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ïŋ―Ōēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÜąäŧŊïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö―Úģïŋ―ïŋ―ČĩÄąäŧŊ
									   {
