/**
  * @brief  ïŋ―ïŋ―ïŋ―ïŋ―PVD.
  * @param  None
  * @retval None
  */
void PVD_Config(void)
{
  NVIC_InitTypeDef NVIC_InitStructure;
  EXTI_InitTypeDef EXTI_InitStructure;

  /*Ęđïŋ―ïŋ― PWR Ęąïŋ―ïŋ― */
  RCC_APB1PeriphClockCmd(RCC_APB1Periph_PWR, ENABLE);

// NVIC_PriorityGroupConfig(NVIC_PriorityGroup_1);

  /* Ęđïŋ―ïŋ― PVD ïŋ―Ðķïŋ― */
  NVIC_InitStructure.NVIC_IRQChannel = PVD_IRQn;
  NVIC_InitStructure.NVIC_IRQChannelPreemptionPriority = 0;
  NVIC_InitStructure.NVIC_IRQChannelSubPriority = 0;
  NVIC_InitStructure.NVIC_IRQChannelCmd = ENABLE;
  NVIC_Init(&NVIC_InitStructure);

  /* ïŋ―ïŋ―ïŋ―ïŋ― EXTI16ïŋ―ïŋ―(PVD ïŋ―ïŋ―ïŋ―) ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Â―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―*/
  EXTI_ClearITPendingBit(EXTI_Line16);
  EXTI_InitStructure.EXTI_Line = EXTI_Line16;
  EXTI_InitStructure.EXTI_Mode = EXTI_Mode_Interrupt;
  EXTI_InitStructure.EXTI_Trigger = EXTI_Trigger_Rising_Falling;
  EXTI_InitStructure.EXTI_LineCmd = ENABLE;
  EXTI_Init(&EXTI_InitStructure);

  /* ïŋ―ïŋ―ïŋ―ïŋ―PVDïŋ―ïŋ―ïŋ―ïŋ―PWR_PVDLevel_2V6 (PVDïŋ―ïŋ―ïŋ―ïŋ―Ņđïŋ―ïŋ―ïŋ―ïŋ―ÖĩÎŠ2.6Vïŋ―ïŋ―VDDïŋ―ïŋ―Ņđïŋ―ïŋ―ïŋ―ïŋ―2.6VĘąïŋ―ïŋ―ïŋ―ïŋ―PVDïŋ―Ðķïŋ―) */
	/*ïŋ―ïŋ―ïŋ―åžķïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ôžïŋ―ïŋ―ïŋ―Ęĩïŋ―ïŋ―ÓĶïŋ―ïŋ―ŌŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
  PWR_PVDLevelConfig(PWR_PVDLevel_2V6);

  /* Ęđïŋ―ïŋ―PVDïŋ―ïŋ―ïŋ― */
  PWR_PVDCmd(ENABLE);
}

