/*
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―RTC_CheckAndConfig
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―éēĒïŋ―ïŋ―ïŋ―ïŋ―RTC
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Úķïŋ―ČĄRTCĘąïŋ―ïŋ―Ä―áđđïŋ―ïŋ―Öļïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―ïŋ―ïŋ―
 */
void RTC_CheckAndConfig(struct rtc_time *tm)
{
   	/*ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―éąļïŋ―ÝžÄīïŋ―ïŋ―ïŋ―BKP_DR1ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýēïŋ―ïŋ―ïŋ―0xA5A5,
	  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―äēĒŅŊïŋ―ïŋ―ïŋ―Ãŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―*/
	if (BKP_ReadBackupRegister(RTC_BKP_DRX) != RTC_BKP_DATA)
	{
		printf("\r\n\r\n RTC not yet configured....");
		printf("\r\n\r\n RTC configured....");

		/* Ęđïŋ―ïŋ―tmïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―RTCïŋ―Äīïŋ―ïŋ―ïŋ― */
		Time_Adjust(tm);

		/*ïŋ―ïŋ―BKP_DR1ïŋ―Äīïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―Öūïŋ―ïŋ―Ëĩïŋ―ïŋ―RTCïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
		BKP_WriteBackupRegister(RTC_BKP_DRX, RTC_BKP_DATA);
	}
	else
	{

		/* Ęđïŋ―ïŋ― PWR ïŋ―ïŋ― Backup Ęąïŋ―ïŋ― */
	  RCC_APB1PeriphClockCmd(RCC_APB1Periph_PWR | RCC_APB1Periph_BKP, ENABLE);

		/* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― Backup ïŋ―ïŋ―ïŋ―ïŋ― */
	  PWR_BackupAccessCmd(ENABLE);

	  /*LSEïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―*/

#ifdef RTC_CLOCK_SOURCE_LSI		
			/* Ęđïŋ―ïŋ― LSI */
			RCC_LSICmd(ENABLE);

			/* ïŋ―Čīïŋ― LSI Ũžïŋ―ïŋ―ïŋ―ïŋ― */
			while (RCC_GetFlagStatus(RCC_FLAG_LSIRDY) == RESET)
			{}
#endif

		/*ïŋ―ïŋ―ïŋ―ïŋ―Į·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
		if (RCC_GetFlagStatus(RCC_FLAG_PORRST) != RESET)
		{
		    printf("\r\n\r\n Power On Reset occurred....");
		}
		/*ïŋ―ïŋ―ïŋ―ïŋ―Į·ïŋ―Resetïŋ―ïŋ―Îŧ*/
		else if (RCC_GetFlagStatus(RCC_FLAG_PINRST) != RESET)
		{
			printf("\r\n\r\n External Reset occurred....");
		}

		printf("\r\n No need to configure RTC....");

		/*ïŋ―Čīïŋ―ïŋ―Äīïŋ―ïŋ―ïŋ―ÍŽïŋ―ïŋ―*/
		RTC_WaitForSynchro();

		/*ïŋ―ïŋ―ïŋ―ïŋ―RTCïŋ―ïŋ―ïŋ―Ðķïŋ―*/
		RTC_ITConfig(RTC_IT_SEC, ENABLE);

		/*ïŋ―Čīïŋ―ïŋ―Ïīïŋ―RTCïŋ―Äīïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
		RTC_WaitForLastTask();
	}
	   /*ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ęĢŽïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĢïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―PC13*/
	#ifdef RTCClockOutput_Enable
	/* Ęđïŋ―ïŋ― PWR ïŋ―ïŋ― Backup Ęąïŋ―ïŋ― */
	  RCC_APB1PeriphClockCmd(RCC_APB1Periph_PWR | RCC_APB1Periph_BKP, ENABLE);

	/* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― Backup ïŋ―ïŋ―ïŋ―ïŋ― */
	  PWR_BackupAccessCmd(ENABLE);

	  /* ïŋ―ïŋ―Öđ Tamper ïŋ―ïŋ―ïŋ―ïŋ― */
	  /* ŌŠïŋ―ïŋ―ïŋ― RTCCLK/64 ïŋ―ïŋ― Tamper ïŋ―ïŋ―ïŋ―ïŋ―,  tamper ïŋ―ïŋ―ïŋ―Üąïŋ―ïŋ―ïŋ―ïŋ―Öđ */	
	  BKP_TamperPinCmd(DISABLE); 

	  /* Ęđïŋ―ïŋ― RTC Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― Tamper ïŋ―ïŋ―ïŋ―ïŋ― */
	  BKP_RTCOutputConfig(BKP_RTCOutputSource_CalibClock);
	#endif

	  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Îŧïŋ―ïŋ―Öū flags */
	  RCC_ClearFlag();

}



/*
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―RTC_Configuration
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―RTC
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―ïŋ―ïŋ―
 */
void RTC_Configuration(void)
{
	/* Ęđïŋ―ïŋ― PWR ïŋ―ïŋ― Backup Ęąïŋ―ïŋ― */
	RCC_APB1PeriphClockCmd(RCC_APB1Periph_PWR | RCC_APB1Periph_BKP, ENABLE);

	/* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― Backup ïŋ―ïŋ―ïŋ―ïŋ― */
	PWR_BackupAccessCmd(ENABLE);

	/* ïŋ―ïŋ―Îŧ Backup ïŋ―ïŋ―ïŋ―ïŋ― */
	BKP_DeInit();

//Ęđïŋ―ïŋ―ïŋ―âēŋĘąïŋ―Óŧïŋ―ïŋ―ïŋ―ïŋ―Úēïŋ―Ęąïŋ―ÓĢïŋ―ïŋ―ïŋ―bsp_rtc.hïŋ―Äžïŋ―ïŋ―ïŋ―ïŋ―åĢĐ	
//Ęđïŋ―ïŋ―ïŋ―âēŋĘąïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĐïŋ―ïŋ―ïŋ―ïŋ―Âūïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Æ·ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ũģïŋ―ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ĖŦïŋ―Éŋïŋ―	
#ifdef 	RTC_CLOCK_SOURCE_LSE
	/* Ęđïŋ―ïŋ― LSE */
	RCC_LSEConfig(RCC_LSE_ON);

	/* ïŋ―Čīïŋ― LSE Ũžïŋ―ïŋ―ïŋ―ïŋ― */
	while (RCC_GetFlagStatus(RCC_FLAG_LSERDY) == RESET)
	{}

	/* ŅĄïŋ―ïŋ― LSE ïŋ―ïŋ―ÎŠ RTC Ęąïŋ―ïŋ―Ôī */
	RCC_RTCCLKConfig(RCC_RTCCLKSource_LSE);

	/* Ęđïŋ―ïŋ― RTC Ęąïŋ―ïŋ― */
	RCC_RTCCLKCmd(ENABLE);

	/* ïŋ―Čīïŋ― RTC ïŋ―Äīïŋ―ïŋ―ïŋ― ÍŽïŋ―ïŋ―
	 * ïŋ―ïŋ―ÎŠRTCĘąïŋ―ïŋ―ïŋ―Įĩïŋ―ïŋ―ŲĩÄĢïŋ―ïŋ―Úŧïŋ―Ęąïŋ―ïŋ―ïŋ―Įļïŋ―ïŋ―ŲĩÄĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŌŠÍŽïŋ―ïŋ―
	 */
	RTC_WaitForSynchro();

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();

	/* Ęđïŋ―ïŋ― RTC ïŋ―ïŋ―ïŋ―Ðķïŋ― */
	RTC_ITConfig(RTC_IT_SEC, ENABLE);

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();

	/* ïŋ―ïŋ―ïŋ―ïŋ― RTC ïŋ―ïŋ―Æĩ: Ęđ RTC ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ1s  */
	/* RTC period = RTCCLK/RTC_PR = (32.768 KHz)/(32767+1) = 1HZ */
	RTC_SetPrescaler(32767); 

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();

#else

	/* Ęđïŋ―ïŋ― LSI */
	RCC_LSICmd(ENABLE);

	/* ïŋ―Čīïŋ― LSI Ũžïŋ―ïŋ―ïŋ―ïŋ― */
	while (RCC_GetFlagStatus(RCC_FLAG_LSIRDY) == RESET)
	{}

	/* ŅĄïŋ―ïŋ― LSI ïŋ―ïŋ―ÎŠ RTC Ęąïŋ―ïŋ―Ôī */
	RCC_RTCCLKConfig(RCC_RTCCLKSource_LSI);

	/* Ęđïŋ―ïŋ― RTC Ęąïŋ―ïŋ― */
	RCC_RTCCLKCmd(ENABLE);

	/* ïŋ―Čīïŋ― RTC ïŋ―Äīïŋ―ïŋ―ïŋ― ÍŽïŋ―ïŋ―
	 * ïŋ―ïŋ―ÎŠRTCĘąïŋ―ïŋ―ïŋ―Įĩïŋ―ïŋ―ŲĩÄĢïŋ―ïŋ―Úŧïŋ―Ęąïŋ―ïŋ―ïŋ―Įļïŋ―ïŋ―ŲĩÄĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŌŠÍŽïŋ―ïŋ―
	 */
	RTC_WaitForSynchro();

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();

	/* Ęđïŋ―ïŋ― RTC ïŋ―ïŋ―ïŋ―Ðķïŋ― */
	RTC_ITConfig(RTC_IT_SEC, ENABLE);

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();

	/* ïŋ―ïŋ―ïŋ―ïŋ― RTC ïŋ―ïŋ―Æĩ: Ęđ RTC ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ1s ,LSIÔžÎŠ40KHz */
	/* RTC period = RTCCLK/RTC_PR = (40 KHz)/(40000-1+1) = 1HZ */	
	RTC_SetPrescaler(40000-1); 

	/* Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ― RTC ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	RTC_WaitForLastTask();
#endif

}



