/*
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Time_Adjust
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Úķïŋ―ČĄRTCĘąïŋ―ïŋ―Ä―áđđïŋ―ïŋ―Öļïŋ―ëĢĻïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―äĢĐ
 * ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―ïŋ―ïŋ―
 */
void Time_Adjust(struct rtc_time *tm)
{

			/* RTC ïŋ―ïŋ―ïŋ―ïŋ― */
		RTC_Configuration();

	  /* ïŋ―Čīïŋ―Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―Îēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	  RTC_WaitForLastTask();

	  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	  GregorianDay(tm);

	  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Úžïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ëĩ―RTCïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äīïŋ―ïŋ―ïŋ― */
	  RTC_SetCounter(mktimev(tm)-TIME_ZOOM);

	  /* ïŋ―Čīïŋ―Č·ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―Îēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
	  RTC_WaitForLastTask();
}

