							if(IO_Status.Target.Air_Door == AIR_CLOSE)//ïŋ―ïŋ―ïŋ―ÅđØąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ßĩïŋ―Æ―ïŋ―ïŋ―ïŋ―ïŋ―
