/*
 * ïŋ―ïŋ―ïŋ―ïŋ― IWDG ïŋ―Äģïŋ―ĘąĘąïŋ―ïŋ―
 * Tout = prv/40 * rlv (s)
 *      prvïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―[4,8,16,32,64,128,256]
 * prv:ÔĪïŋ―ïŋ―Æĩïŋ―ïŋ―Öĩïŋ―ïŋ―ČĄÖĩïŋ―ïŋ―ïŋ―ÂĢïŋ―
 *     @arg IWDG_Prescaler_4: IWDG prescaler set to 4
 *     @arg IWDG_Prescaler_8: IWDG prescaler set to 8
 *     @arg IWDG_Prescaler_16: IWDG prescaler set to 16
 *     @arg IWDG_Prescaler_32: IWDG prescaler set to 32
 *     @arg IWDG_Prescaler_64: IWDG prescaler set to 64
 *     @arg IWDG_Prescaler_128: IWDG prescaler set to 128
 *     @arg IWDG_Prescaler_256: IWDG prescaler set to 256
 *
 * rlv:ÔĪïŋ―ïŋ―Æĩïŋ―ïŋ―Öĩïŋ―ïŋ―ČĄÖĩïŋ―ïŋ―Î§ÎŠïŋ―ïŋ―0-0XFFF
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ãūïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
 * IWDG_Config(IWDG_Prescaler_64 ,625);  // IWDG 1s ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―
 */

void IWDG_Config(uint8_t prv ,uint16_t rlv)
{	
	// Ęđïŋ―ïŋ― ÔĪïŋ―ïŋ―Æĩïŋ―Äīïŋ―ïŋ―ïŋ―PRïŋ―ïŋ―ïŋ―ïŋ―Ũ°ïŋ―ØžÄīïŋ―ïŋ―ïŋ―RLRïŋ―ïŋ―Ðī
	IWDG_WriteAccessCmd( IWDG_WriteAccess_Enable );

	// ïŋ―ïŋ―ïŋ―ïŋ―ÔĪïŋ―ïŋ―Æĩïŋ―ïŋ―Öĩ
	IWDG_SetPrescaler( prv );

	// ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ũ°ïŋ―ØžÄīïŋ―ïŋ―ïŋ―Öĩ
	IWDG_SetReload( rlv );

	// ïŋ―ïŋ―ïŋ―ïŋ―Ũ°ïŋ―ØžÄīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―Åĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	IWDG_ReloadCounter();

	// Ęđïŋ―ïŋ― IWDG
	IWDG_Enable();	
}

// Îđïŋ―ïŋ―
void IWDG_Feed(void)
{
	// ïŋ―ïŋ―ïŋ―ïŋ―Ũ°ïŋ―ØžÄīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―Åĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĢïŋ―Îđïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÖđIWDGïŋ―ïŋ―Îŧ
	// ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―ïŋ―ïŋ―ïŋ―0ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÏĩÍģïŋ―ïŋ―Îŧ
	IWDG_ReloadCounter();
}


