//ïŋ―ïŋ―ïŋ―Ęđïŋ―ïŋ―ucosII,delay_initïŋ―ïŋ―ïŋ―Ôķïŋ―ïŋ―ïŋ―ïŋ―ïŋ―SYSTICKïŋ―ïŋ―Öĩ,ĘđÖŪïŋ―ïŋ―ucosïŋ―ïŋ―TICKS_PER_SECïŋ―ïŋ―ÓĶ.
//delay_msïŋ―ïŋ―delay_usŌēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―Äļïŋ―ïŋ―ïŋ―.
//delay_usïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―Ęđïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―ŨžČ·ïŋ―ČšÜļïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―ŌŠïŋ―ïŋ―ïŋ―ïŋ―Ãŧïŋ―ïŋ―Õžïŋ―Ãķïŋ―ïŋ―ïŋ―Äķïŋ―Ęąïŋ―ïŋ―.
//delay_msïŋ―ïŋ―ucosïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―Ôĩïŋ―ïŋ―ïŋ―OSTimeDlyïŋ―ïŋ―ïŋ―ïŋ―,ïŋ―ïŋ―Îīïŋ―ïŋ―ïŋ―ïŋ―ucosĘą,ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―delay_usĘĩïŋ―ïŋ―,ïŋ―Óķïŋ―ŨžČ·ïŋ―ïŋ―Ęą
//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ucosÖŪïŋ―ïŋ―delay_msïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―Äģïŋ―ïŋ―ïŋ―,ŅĄïŋ―ïŋ―OSTimeDlyĘĩïŋ―Öŧïŋ―ïŋ―ïŋ―delay_usĘĩïŋ―ïŋ―.

//V1.4ïŋ―Þļïŋ―Ëĩïŋ―ïŋ― 20110929
//ïŋ―Þļïŋ―ïŋ―ïŋ―Ęđïŋ―ïŋ―ucos,ïŋ―ïŋ―ïŋ―ïŋ―ucosÎīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―,delay_msïŋ―ïŋ―ïŋ―Ðķïŋ―ïŋ―Þ·ïŋ―ïŋ―ïŋ―ÓĶïŋ―ïŋ―bug.
//V1.5ïŋ―Þļïŋ―Ëĩïŋ―ïŋ― 20120902
//ïŋ―ïŋ―delay_usïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öđïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―ïŋ―delay_usïŋ―ïŋ―Öīïŋ―ÐĢïŋ―ïŋ―ïŋ―ïŋ―Üĩïŋ―ïŋ―Âĩïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―Ũžïŋ―ïŋ―
////////////////////////////////////////////////////////////////////////////////// 	 
static u8  fac_us=0;//usïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
static u16 fac_ms=0;//msïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
#ifdef OS_CRITICAL_METHOD 	//ïŋ―ïŋ―ïŋ―OS_CRITICAL_METHODïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,Ëĩïŋ―ïŋ―Ęđïŋ―ïŋ―ucosIIïŋ―ïŋ―.
//systickïŋ―ÐķÏ·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,Ęđïŋ―ïŋ―ucosĘąïŋ―Ãĩïŋ―
void SysTick_Handler(void)
{				   
	OSIntEnter();		//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
    OSTimeTick();       //ïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―Ęąïŋ―Ó·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―               
    OSIntExit();        //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðŧïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
}
#endif

//ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ÓģŲšïŋ―ïŋ―ïŋ―
//ïŋ―ïŋ―Ęđïŋ―ïŋ―ucosïŋ―ïŋ―Ęąïŋ―ïŋ―,ïŋ―Ëšïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęžïŋ―ïŋ―ucosïŋ―ïŋ―Ęąïŋ―Ó―ïŋ―ïŋ―ïŋ―
//SYSTICKïŋ―ïŋ―Ęąïŋ―ÓđĖķïŋ―ÎŠHCLKĘąïŋ―Óĩïŋ―1/8
//SYSCLK:ÏĩÍģĘąïŋ―ïŋ―
void delay_init()	 
{

#ifdef OS_CRITICAL_METHOD 	//ïŋ―ïŋ―ïŋ―OS_CRITICAL_METHODïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,Ëĩïŋ―ïŋ―Ęđïŋ―ïŋ―ucosIIïŋ―ïŋ―.
	u32 reload;
#endif
	SysTick_CLKSourceConfig(SysTick_CLKSource_HCLK_Div8);	//ŅĄïŋ―ïŋ―ïŋ―âēŋĘąïŋ―ïŋ―  HCLK/8
	fac_us=SystemCoreClock/8000000;	//ÎŠÏĩÍģĘąïŋ―Óĩïŋ―1/8  

#ifdef OS_CRITICAL_METHOD 	//ïŋ―ïŋ―ïŋ―OS_CRITICAL_METHODïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,Ëĩïŋ―ïŋ―Ęđïŋ―ïŋ―ucosIIïŋ―ïŋ―.
	reload=SystemCoreClock/8000000;		//Ãŋïŋ―ïŋ―ïŋ―ÓĩÄžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― ïŋ―ïŋ―ÎŧÎŠK	   
	reload*=1000000/OS_TICKS_PER_SEC;//ïŋ―ïŋ―ïŋ―ïŋ―OS_TICKS_PER_SECïŋ―čķĻïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―
							//reloadÎŠ24Îŧïŋ―Äīïŋ―ïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―Öĩ:16777216,ïŋ―ïŋ―72Mïŋ―ïŋ―,Ôžïŋ―ïŋ―1.86sïŋ―ïŋ―ïŋ―ïŋ―	
	fac_ms=1000/OS_TICKS_PER_SEC;//ïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ųĩïŋ―Îŧ	   
	SysTick->CTRL|=SysTick_CTRL_TICKINT_Msk;   	//ïŋ―ïŋ―ïŋ―ïŋ―SYSTICKïŋ―Ðķïŋ―
	SysTick->LOAD=reload; 	//Ãŋ1/OS_TICKS_PER_SECïŋ―ïŋ―ïŋ―Ðķïŋ―Ōŧïŋ―ïŋ―	
	SysTick->CTRL|=SysTick_CTRL_ENABLE_Msk;   	//ïŋ―ïŋ―ïŋ―ïŋ―SYSTICK    
#else
	fac_ms=(u16)fac_us*1000;//ïŋ―ïŋ―ucosïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―Ãŋïŋ―ïŋ―msïŋ―ïŋ―ŌŠïŋ―ïŋ―systickĘąïŋ―ïŋ―ïŋ―ïŋ―   
#endif
}								    

#ifdef OS_CRITICAL_METHOD	//Ęđïŋ―ïŋ―ïŋ―ïŋ―ucos
//ïŋ―ïŋ―Ęąnus
//nusÎŠŌŠïŋ―ïŋ―Ęąïŋ―ïŋ―usïŋ―ïŋ―.		    								   
void delay_us(u32 nus)
{		
	u32 ticks;
	u32 told,tnow,tcnt=0;
	u32 reload=SysTick->LOAD;	//LOADïŋ―ïŋ―Öĩ	    	 
	ticks=nus*fac_us; 			//ïŋ―ïŋ―ŌŠïŋ―Ä―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	  		 
	tcnt=0;
	told=SysTick->VAL;        	//ïŋ―Õ―ïŋ―ïŋ―ïŋ―Ęąïŋ―Äžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
	while(1)
	{
		tnow=SysTick->VAL;	
		if(tnow!=told)
		{	    
			if(tnow<told)tcnt+=told-tnow;//ïŋ―ïŋ―ïŋ―ïŋ―ŨĒïŋ―ïŋ―Ōŧïŋ―ïŋ―SYSTICKïŋ―ïŋ―Ōŧïŋ―ïŋ―ïŋ―Ýžïŋ―ïŋ―Äžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Íŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―.
			else tcnt+=reload-tnow+told;	    
			told=tnow;
			if(tcnt>=ticks)break;//Ęąïŋ―äģŽïŋ―ïŋ―/ïŋ―ïŋ―ïŋ―ïŋ―ŌŠïŋ―ÓģŲĩïŋ―Ęąïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―Ëģïŋ―.
		}  
	}; 									    
}
//ïŋ―ïŋ―Ęąnms
//nms:ŌŠïŋ―ïŋ―Ęąïŋ―ïŋ―msïŋ―ïŋ―
void delay_ms(u16 nms)
{	
	if(OSRunning==TRUE)//ïŋ―ïŋ―ïŋ―osïŋ―Ņūïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	    
	{		  
		if(nms>=fac_ms)//ïŋ―ïŋ―Ęąïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ucosïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― 
		{
   			OSTimeDly(nms/fac_ms);//ucosïŋ―ïŋ―Ęą
		}
		nms%=fac_ms;				//ucosïŋ―Ņūïŋ―ïŋ―Þ·ïŋ―ïŋ―áđĐïŋ―ïŋ―ÃīÐĄïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÍĻïŋ―ïŋ―Ę―ïŋ―ïŋ―Ęą    
	}
	delay_us((u32)(nms*1000));	//ïŋ―ïŋ―ÍĻïŋ―ïŋ―Ę―ïŋ―ïŋ―Ęą,ïŋ―ïŋ―Ęąucosïŋ―Þ·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―.
}
#else//ïŋ―ïŋ―ïŋ―ïŋ―ucosĘą
//ïŋ―ïŋ―Ęąnus
//nusÎŠŌŠïŋ―ïŋ―Ęąïŋ―ïŋ―usïŋ―ïŋ―.		    								   
void delay_us(u32 nus)
{		
	u32 temp;	    	 
	SysTick->LOAD=nus*fac_us; //Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	  		 
	SysTick->VAL=0x00;        //ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	SysTick->CTRL|=SysTick_CTRL_ENABLE_Msk ;          //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―	 
	do
	{
		temp=SysTick->CTRL;
	}
	while(temp&0x01&&!(temp&(1<<16)));//ïŋ―Čīïŋ―Ęąïŋ―äĩ―ïŋ―ïŋ―   
	SysTick->CTRL&=~SysTick_CTRL_ENABLE_Msk;       //ïŋ―ØąÕžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	SysTick->VAL =0X00;       //ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	 
}
//ïŋ―ïŋ―Ęąnms
//ŨĒïŋ―ïŋ―nmsïŋ―Ä·ïŋ―Î§
//SysTick->LOADÎŠ24Îŧïŋ―Äīïŋ―ïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―,ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ĘąÎŠ:
//nms<=0xffffff*8*1000/SYSCLK
//SYSCLKïŋ―ïŋ―ÎŧÎŠHz,nmsïŋ―ïŋ―ÎŧÎŠms
//ïŋ―ïŋ―72Mïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―,nms<=1864 
void delay_ms(u16 nms)
{	 		  	  
	u32 temp;		   
	SysTick->LOAD=(u32)nms*fac_ms;//Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―(SysTick->LOADÎŠ24bit)
	SysTick->VAL =0x00;           //ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	SysTick->CTRL|=SysTick_CTRL_ENABLE_Msk ;          //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―  
	do
	{
		temp=SysTick->CTRL;
	}
	while(temp&0x01&&!(temp&(1<<16)));//ïŋ―Čīïŋ―Ęąïŋ―äĩ―ïŋ―ïŋ―   
	SysTick->CTRL&=~SysTick_CTRL_ENABLE_Msk;       //ïŋ―ØąÕžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	SysTick->VAL =0X00;       //ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	  	    
} 



void delay_sys_sec(u32 nms)
{
			sys_control_time = nms;
			sys_time_up = false;   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öūïŋ―ïŋ―ïŋ―ïŋ―
	    sys_time_start = true;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öū
}


void delay_time_ms(uint16 nms)
{
	sys_flag.sys_delay_time = nms;
	sys_flag.sys_delay_up = false;
	sys_flag.sys_delay_start = true;

}

