/**
  * @brief  SPI_FLASHïŋ―ïŋ―Ęžïŋ―ïŋ―
  * @param  ïŋ―ïŋ―
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_Init(void)
{
  SPI_InitTypeDef  SPI_InitStructure;
  GPIO_InitTypeDef GPIO_InitStructure;



	/* Ęđïŋ―ïŋ―SPIĘąïŋ―ïŋ― */
	RCC_APB1PeriphClockCmd(RCC_APB1Periph_SPI3, ENABLE);

	/* Ęđïŋ―ïŋ―SPIïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Øĩïŋ―Ęąïŋ―ïŋ― */
 	RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOA | RCC_APB2Periph_GPIOB | RCC_APB2Periph_AFIO, ENABLE);
	GPIO_PinRemapConfig(GPIO_Remap_SWJ_JTAGDisable, ENABLE);

  //SPI_FLASH_SPI pins: SCK--PB3
  GPIO_InitStructure.GPIO_Pin = GPIO_Pin_3;
  GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AF_PP;
  GPIO_Init(GPIOB, &GPIO_InitStructure);

  //SPI_FLASH_SPI pins: MISO--PB4
  GPIO_InitStructure.GPIO_Pin = GPIO_Pin_4;
  GPIO_Init(GPIOB, &GPIO_InitStructure);

  //SPI_FLASH_SPI pins: MOSI--PB5 
  GPIO_InitStructure.GPIO_Pin = GPIO_Pin_5;
  GPIO_Init(GPIOB, &GPIO_InitStructure);

   //SPI_FLASH_SPI_CS_PIN pin: CS---PB6

   GPIO_InitStructure.GPIO_Pin = GPIO_Pin_6;
  GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_Out_PP;	
  GPIO_Init(GPIOB, &GPIO_InitStructure);


  //SPI_FLASH_SPI_CS_PIN pin: CS--PA15
  GPIO_InitStructure.GPIO_Pin = GPIO_Pin_15;
  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_Out_PP;
  GPIO_Init(GPIOA, &GPIO_InitStructure);
  /* ÍĢÖđïŋ―Åšïŋ― FLASH: CSïŋ―ïŋ―ïŋ―Åļßĩïŋ―Æ―*/
  SPI_FLASH_CS_HIGH();

  /* SPI ÄĢĘ―ïŋ―ïŋ―ïŋ―ïŋ― */
  // FLASHÐūÆŽ Ö§ïŋ―ïŋ―SPIÄĢĘ―0ïŋ―ïŋ―ÄĢĘ―3ïŋ―ïŋ―ïŋ―Ýīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―CPOL CPHA
  SPI_InitStructure.SPI_Direction = SPI_Direction_2Lines_FullDuplex;
  SPI_InitStructure.SPI_Mode = SPI_Mode_Master;
  SPI_InitStructure.SPI_DataSize = SPI_DataSize_8b;
  SPI_InitStructure.SPI_CPOL = SPI_CPOL_High;
  SPI_InitStructure.SPI_CPHA = SPI_CPHA_2Edge;
  SPI_InitStructure.SPI_NSS = SPI_NSS_Soft;
 // SPI_InitStructure.SPI_BaudRatePrescaler = SPI_BaudRatePrescaler_4;//ïŋ―ïŋ―Ōŧïŋ―ïŋ―ïŋ―æąūÎŠ4ïŋ―ïŋ―Æĩ
 SPI_InitStructure.SPI_BaudRatePrescaler = SPI_BaudRatePrescaler_8;
  SPI_InitStructure.SPI_FirstBit = SPI_FirstBit_MSB;
  SPI_InitStructure.SPI_CRCPolynomial = 7;
  SPI_Init(FLASH_SPIx , &SPI_InitStructure);

  /* Ęđïŋ―ïŋ― SPI  */
  SPI_Cmd(FLASH_SPIx , ENABLE);

}
 /**
  * @brief  ïŋ―ïŋ―ïŋ―ïŋ―FLASHïŋ―ïŋ―ïŋ―ïŋ―
  * @param  SectorAddrïŋ―ïŋ―ŌŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_SectorErase(u32 SectorAddr)
{
  /* ïŋ―ïŋ―ïŋ―ïŋ―FLASHÐīĘđïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  SPI_FLASH_WriteEnable();
  SPI_FLASH_WaitForWriteEnd();
  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  /* ŅĄïŋ―ïŋ―FLASH: CSïŋ―Íĩïŋ―Æ― */
  SPI_FLASH_CS_LOW();
  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―*/
  SPI_FLASH_SendByte(W25X_SectorErase);
  /*ïŋ―ïŋ―ïŋ―Íēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―Äļïŋ―Îŧ*/
  SPI_FLASH_SendByte((SectorAddr & 0xFF0000) >> 16);
  /* ïŋ―ïŋ―ïŋ―Íēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―Îŧ */
  SPI_FLASH_SendByte((SectorAddr & 0xFF00) >> 8);
  /* ïŋ―ïŋ―ïŋ―Íēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―Äĩïŋ―Îŧ */
  SPI_FLASH_SendByte(SectorAddr & 0xFF);
  /* ÍĢÖđïŋ―Åšïŋ― FLASH: CS ïŋ―ßĩïŋ―Æ― */
  SPI_FLASH_CS_HIGH();
  /* ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
  SPI_FLASH_WaitForWriteEnd();
}

 /**
  * @brief  ïŋ―ïŋ―ïŋ―ïŋ―FLASHïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÆŽïŋ―ïŋ―ïŋ―ïŋ―
  * @param  ïŋ―ïŋ―
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_BulkErase(void)
{
  /* ïŋ―ïŋ―ïŋ―ïŋ―FLASHÐīĘđïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  SPI_FLASH_WriteEnable();

  /* ïŋ―ïŋ―ïŋ―ïŋ― Erase */
  /* ŅĄïŋ―ïŋ―FLASH: CSïŋ―Íĩïŋ―Æ― */
  SPI_FLASH_CS_LOW();
  /* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―*/
  SPI_FLASH_SendByte(W25X_ChipErase);
  /* ÍĢÖđïŋ―Åšïŋ― FLASH: CS ïŋ―ßĩïŋ―Æ― */
  SPI_FLASH_CS_HIGH();

  /* ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
  SPI_FLASH_WaitForWriteEnd();
}

 /**
  * @brief  ïŋ―ïŋ―FLASHïŋ―ïŋ―ŌģÐīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ïŋ―ïŋ―ïŋ―Ãąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Į°ïŋ―ïŋ―ŌŠïŋ―Čēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
  * @param	pBufferïŋ―ïŋ―ŌŠÐīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýĩïŋ―Öļïŋ―ïŋ―
  * @param WriteAddrïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―Ö·
  * @param  NumByteToWriteïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ČĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĄïŋ―Úĩïŋ―ïŋ―ïŋ―SPI_FLASH_PerWritePageSize
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_PageWrite(u8* pBuffer, u32 WriteAddr, u16 NumByteToWrite)
{
  /* ïŋ―ïŋ―ïŋ―ïŋ―FLASHÐīĘđïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  SPI_FLASH_WriteEnable();

  /* ŅĄïŋ―ïŋ―FLASH: CSïŋ―Íĩïŋ―Æ― */
  SPI_FLASH_CS_LOW();
  /* ÐīŌģÐīÖļïŋ―ïŋ―*/
  SPI_FLASH_SendByte(W25X_PageProgram);
  /*ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―Ö·ïŋ―Äļïŋ―Îŧ*/
  SPI_FLASH_SendByte((WriteAddr & 0xFF0000) >> 16);
  /*ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―Îŧ*/
  SPI_FLASH_SendByte((WriteAddr & 0xFF00) >> 8);
  /*ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―Ö·ïŋ―Äĩïŋ―Îŧ*/
  SPI_FLASH_SendByte(WriteAddr & 0xFF);

  if(NumByteToWrite > SPI_FLASH_PerWritePageSize)
  {
     NumByteToWrite = SPI_FLASH_PerWritePageSize;
     FLASH_ERROR("SPI_FLASH_PageWrite too large!"); 
  }

  /* Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
  while (NumByteToWrite--)
  {
    /* ïŋ―ïŋ―ïŋ―Íĩïŋ―Į°ŌŠÐīïŋ―ïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
    SPI_FLASH_SendByte(*pBuffer);
    /* Öļïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
    pBuffer++;
  }

  /* ÍĢÖđïŋ―Åšïŋ― FLASH: CS ïŋ―ßĩïŋ―Æ― */
  SPI_FLASH_CS_HIGH();

  /* ïŋ―Čīïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
  SPI_FLASH_WaitForWriteEnd();
}

 /**
  * @brief  ïŋ―ïŋ―FLASHÐīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ïŋ―ïŋ―ïŋ―Ãąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Į°ïŋ―ïŋ―ŌŠïŋ―Čēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
  * @param	pBufferïŋ―ïŋ―ŌŠÐīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýĩïŋ―Öļïŋ―ïŋ―
  * @param  WriteAddrïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―Ö·
  * @param  NumByteToWriteïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ïŋ―
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_BufferWrite(u8* pBuffer, u32 WriteAddr, u16 NumByteToWrite)
{
  u8 NumOfPage = 0, NumOfSingle = 0, Addr = 0, count = 0, temp = 0;

	/*modïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―āĢŽïŋ―ïŋ―writeAddrïŋ―ïŋ―SPI_FLASH_PageSizeïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―AddrÖĩÎŠ0*/
  Addr = WriteAddr % SPI_FLASH_PageSize;

	/*ïŋ―ïŋ―countïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―ïŋ―ïŋ―ÕšÃŋïŋ―ïŋ―Ôķïŋ―ïŋ―ëĩ―Ōģïŋ―ïŋ―Ö·*/
  count = SPI_FLASH_PageSize - Addr;
	/*ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŌŠÐīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ōģ*/
  NumOfPage =  NumByteToWrite / SPI_FLASH_PageSize;
	/*modïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―āĢŽïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ĘĢïŋ―āēŧïŋ―ïŋ―ŌŧŌģïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―*/
  NumOfSingle = NumByteToWrite % SPI_FLASH_PageSize;

	/* Addr=0,ïŋ―ïŋ―WriteAddr ïŋ―ÕšÃ°ïŋ―Ōģïŋ―ïŋ―ïŋ―ïŋ― aligned  */
  if (Addr == 0)
  {
		/* NumByteToWrite < SPI_FLASH_PageSize */
    if (NumOfPage == 0) 
    {
      SPI_FLASH_PageWrite(pBuffer, WriteAddr, NumByteToWrite);
    }
    else /* NumByteToWrite > SPI_FLASH_PageSize */
    { 
			/*ïŋ―Č°ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ōģïŋ―ïŋ―Ðīïŋ―ïŋ―*/
      while (NumOfPage--)
      {
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, SPI_FLASH_PageSize);
        WriteAddr +=  SPI_FLASH_PageSize;
        pBuffer += SPI_FLASH_PageSize;
      }
			/*ïŋ―ïŋ―ïŋ―Ðķïŋ―ïŋ―ïŋ―Äēïŋ―ïŋ―ïŋ―ŌŧŌģïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―*/
      SPI_FLASH_PageWrite(pBuffer, WriteAddr, NumOfSingle);
    }
  }
	/* ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ― SPI_FLASH_PageSize ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―  */
  else 
  {
		/* NumByteToWrite < SPI_FLASH_PageSize */
    if (NumOfPage == 0)
    {
			/*ïŋ―ïŋ―Į°ŌģĘĢïŋ―ïŋ―ïŋ―countïŋ―ïŋ―Îŧïŋ―Ãąïŋ―NumOfSingleÐĄïŋ―ïŋ―ŌŧŌģÐīïŋ―ïŋ―ïŋ―ïŋ―*/
      if (NumOfSingle > count) 
      {
        temp = NumOfSingle - count;
				/*ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―ïŋ―Į°Ōģ*/
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, count);

        WriteAddr +=  count;
        pBuffer += count;
				/*ïŋ―ïŋ―ÐīĘĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, temp);
      }
      else /*ïŋ―ïŋ―Į°ŌģĘĢïŋ―ïŋ―ïŋ―countïŋ―ïŋ―Îŧïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―NumOfSingleïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
      {
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, NumByteToWrite);
      }
    }
    else /* NumByteToWrite > SPI_FLASH_PageSize */
    {
			/*ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―countïŋ―Öŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―*/
      NumByteToWrite -= count;
      NumOfPage =  NumByteToWrite / SPI_FLASH_PageSize;
      NumOfSingle = NumByteToWrite % SPI_FLASH_PageSize;

			/* ïŋ―ïŋ―Ðīïŋ―ïŋ―countïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ÎŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ―ŌŠÐīïŋ―Äĩïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ― */
      SPI_FLASH_PageWrite(pBuffer, WriteAddr, count);

			/* ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Øļïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
      WriteAddr +=  count;
      pBuffer += count;
			/*ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ōģïŋ―ïŋ―Ðīïŋ―ïŋ―*/
      while (NumOfPage--)
      {
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, SPI_FLASH_PageSize);
        WriteAddr +=  SPI_FLASH_PageSize;
        pBuffer += SPI_FLASH_PageSize;
      }
			/*ïŋ―ïŋ―ïŋ―Ðķïŋ―ïŋ―ïŋ―Äēïŋ―ïŋ―ïŋ―ŌŧŌģïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÝĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―*/
      if (NumOfSingle != 0)
      {
        SPI_FLASH_PageWrite(pBuffer, WriteAddr, NumOfSingle);
      }
    }
  }
}

 /**
  * @brief  ïŋ―ïŋ―ČĄFLASHïŋ―ïŋ―ïŋ―ïŋ―
  * @param 	pBufferïŋ―ïŋ―ïŋ―æīĒïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýĩïŋ―Öļïŋ―ïŋ―
  * @param   ReadAddrïŋ―ïŋ―ïŋ―ïŋ―ČĄïŋ―ïŋ―Ö·
  * @param   NumByteToReadïŋ―ïŋ―ïŋ―ïŋ―ČĄïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ïŋ―
  * @retval ïŋ―ïŋ―
  */
void SPI_FLASH_BufferRead(u8* pBuffer, u32 ReadAddr, u16 NumByteToRead)
{
  /* ŅĄïŋ―ïŋ―FLASH: CSïŋ―Íĩïŋ―Æ― */
  SPI_FLASH_CS_LOW();

  /* ïŋ―ïŋ―ïŋ―ïŋ― ïŋ―ïŋ― Öļïŋ―ïŋ― */
  SPI_FLASH_SendByte(W25X_ReadData);

  /* ïŋ―ïŋ―ïŋ―ïŋ― ïŋ―ïŋ― ïŋ―ïŋ―Ö·ïŋ―ïŋ―Îŧ */
  SPI_FLASH_SendByte((ReadAddr & 0xFF0000) >> 16);
  /* ïŋ―ïŋ―ïŋ―ïŋ― ïŋ―ïŋ― ïŋ―ïŋ―Ö·ïŋ―ïŋ―Îŧ */
  SPI_FLASH_SendByte((ReadAddr& 0xFF00) >> 8);
  /* ïŋ―ïŋ―ïŋ―ïŋ― ïŋ―ïŋ― ïŋ―ïŋ―Ö·ïŋ―ïŋ―Îŧ */
  SPI_FLASH_SendByte(ReadAddr & 0xFF);

	/* ïŋ―ïŋ―ČĄïŋ―ïŋ―ïŋ―ïŋ― */
  while (NumByteToRead--) /* while there is data to be read */
  {
    /* ïŋ―ïŋ―ČĄŌŧïŋ―ïŋ―ïŋ―Ö―ïŋ―*/
    *pBuffer = SPI_FLASH_SendByte(Dummy_Byte);
    /* Öļïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ―ïŋ―Ö―Úŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
    pBuffer++;
  }

  /* ÍĢÖđïŋ―Åšïŋ― FLASH: CS ïŋ―ßĩïŋ―Æ― */
  SPI_FLASH_CS_HIGH();
}

 /**
  * @brief  ïŋ―ïŋ―ČĄFLASH ID
  * @param 	ïŋ―ïŋ―
  * @retval FLASH ID
  */
u32 SPI_FLASH_ReadID(void)
{
  u32 Temp = 0, Temp0 = 0, Temp1 = 0, Temp2 = 0;

  /* ïŋ―ïŋ―ĘžÍĻŅķïŋ―ïŋ―CSïŋ―Íĩïŋ―Æ― */
  SPI_FLASH_CS_LOW();

  /* ïŋ―ïŋ―ïŋ―ïŋ―JEDECÖļïŋ―îĢŽïŋ―ïŋ―ČĄID */
  SPI_FLASH_SendByte(W25X_JedecDeviceID);

  /* ïŋ―ïŋ―ČĄŌŧïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  Temp0 = SPI_FLASH_SendByte(Dummy_Byte);

  /* ïŋ―ïŋ―ČĄŌŧïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  Temp1 = SPI_FLASH_SendByte(Dummy_Byte);

  /* ïŋ―ïŋ―ČĄŌŧïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ― */
  Temp2 = SPI_FLASH_SendByte(Dummy_Byte);

 /* ÍĢÖđÍĻŅķïŋ―ïŋ―CSïŋ―ßĩïŋ―Æ― */
  SPI_FLASH_CS_HIGH();

  /*ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÎŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ä·ïŋ―ïŋ―ïŋ―Öĩ*/
	Temp = (Temp0 << 16) | (Temp1 << 8) | Temp2;

  return Temp;
}
 /**
  * @brief  ïŋ―ïŋ―ČĄFLASH Device ID
  * @param 	ïŋ―ïŋ―
  * @retval FLASH Device ID
  */
u32 SPI_FLASH_ReadDeviceID(void)
{
  u32 Temp = 0;

  /* Select the FLASH: Chip Select low */
  SPI_FLASH_CS_LOW();

  /* Send "RDID " instruction */
  SPI_FLASH_SendByte(W25X_DeviceID);
  SPI_FLASH_SendByte(Dummy_Byte);
  SPI_FLASH_SendByte(Dummy_Byte);
  SPI_FLASH_SendByte(Dummy_Byte);

  /* Read a byte from the FLASH */
  Temp = SPI_FLASH_SendByte(Dummy_Byte);

  /* Deselect the FLASH: Chip Select high */
  SPI_FLASH_CS_HIGH();

  return Temp;
}
