void send_product_name(void)
{
	uint8 temp = 0;

		send_byte(0x5A);
		send_byte(0XA5);
		send_byte(3+2*sizeof(product_name));//ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
		send_byte(0X82);//Ðīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
		send_byte(0X03);
		send_byte(0X90);//ïŋ―ïŋ―Ęžïŋ―ïŋ―Ö·

		for(temp = 0; temp < sizeof(product_name);temp++ )
			{
				send_byte(0X00);
				send_byte(product_name[temp]);
			}

}

