uint8 ModuBusRTU_WriteResponse(uint16 address,uint16 Data16)
{
	uint16 check_sum = 0;
	uint8 Device_ID = 1;

		if(U1_Inf.RX_Data[0] > 1)
		{
			//ïŋ―ïŋ―ïŋ―ïŋ―ŅŊïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―1Ęąïŋ―ïŋ―ïŋ―Ôķïŋ―ïŋ―Ðŧïŋ―ÎŠïŋ―Ô·ïŋ―ŅŊïŋ―ĘĩÄĩïŋ―Ö·
			Device_ID = Sys_Admin.ModBus_Address;
		}
	U1_Inf.TX_Data[0] = Device_ID;

	U1_Inf.TX_Data[1]= 0x06;


	U1_Inf.TX_Data[2] = address >> 8;    // ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―Ö―ïŋ―
	U1_Inf.TX_Data[3] = address & 0x00FF;  //ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―Ö―ïŋ―


	U1_Inf.TX_Data[4] = Data16 >> 8;  //ïŋ―ïŋ―ïŋ―Ýļïŋ―ïŋ―Ö―ïŋ―
	U1_Inf.TX_Data[5] = Data16 & 0x00FF;   //ïŋ―ïŋ―ïŋ―Ýĩïŋ―ïŋ―Ö―ïŋ―

	check_sum  = ModBusCRC16(U1_Inf.TX_Data,8);   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―Äąïŋ―
	U1_Inf.TX_Data[6]  = check_sum >> 8 ;
	U1_Inf.TX_Data[7]  = check_sum & 0x00FF;

	Usart_SendStr_length(USART1,U1_Inf.TX_Data,8);

	return 0;
}



uint8 ModuBusRTU_Write0x10Response(uint16 address,uint16 Data16)
{
	uint16 check_sum = 0;
	uint8 Device_ID = 1;

	if(U1_Inf.RX_Data[0] >= 1)
		{
			//ïŋ―ïŋ―ïŋ―ïŋ―ŅŊïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―1Ęąïŋ―ïŋ―ïŋ―Ôķïŋ―ïŋ―Ðŧïŋ―ÎŠïŋ―Ô·ïŋ―ŅŊïŋ―ĘĩÄĩïŋ―Ö·
			Device_ID = Sys_Admin.ModBus_Address;
		}

	U1_Inf.TX_Data[0] = Device_ID; 
	U1_Inf.TX_Data[1]= 0x10;

	U1_Inf.TX_Data[2] = address >> 8;    // ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―Ö―ïŋ―
	U1_Inf.TX_Data[3] = address & 0x00FF;  //ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―Ö―ïŋ―

	U1_Inf.TX_Data[4] = Data16 >> 8;  // 
	U1_Inf.TX_Data[5] = Data16 & 0X00FF;    

	check_sum  = ModBusCRC16(U1_Inf.TX_Data,8);   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö―ïŋ―ïŋ―ïŋ―ïŋ―Äąïŋ―
	U1_Inf.TX_Data[6]  = check_sum >> 8 ;
	U1_Inf.TX_Data[7]  = check_sum & 0x00FF;

	Usart_SendStr_length(USART1,U1_Inf.TX_Data,8);




		return 0;
}



