void U5_Printf(char* fmt,...)  
{  
  int len=0;
	int cnt=0;

	va_list ap;
	va_start(ap,fmt);
	vsprintf((char*)U5_Inf.TX_Data,fmt,ap);
	va_end(ap);
	len = strlen((const char*)U5_Inf.TX_Data);
	while(len--)
	  {
	  while(USART_GetFlagStatus(UART5,USART_FLAG_TC)!=1); //ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―Í―ïŋ―ïŋ―ïŋ―
	  	USART_SendData(UART5,U5_Inf.TX_Data[cnt++]);
	  }
}










