void uart4_init(u32 bound)
{  	 		 
	//GPIOïŋ―Ëŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_InitTypeDef GPIO_InitStructure;
	USART_InitTypeDef USART_InitStructure;
	NVIC_InitTypeDef NVIC_InitStructure;

	RCC_APB1PeriphClockCmd(RCC_APB1Periph_UART4, ENABLE);	//Ęđïŋ―ïŋ―USART4
	RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOC, ENABLE);	//Ęđïŋ―ïŋ―GPIOCĘąïŋ―ïŋ―
	USART_DeInit(UART4);  //ïŋ―ïŋ―Îŧïŋ―ïŋ―ïŋ―ïŋ―4

     //USART4_TX   PC.10
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_10; //PC.10
    GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
    GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AF_PP;	//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_Init(GPIOC, &GPIO_InitStructure);

    //USART4_RX	  PC.11
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_11;
    GPIO_InitStructure.GPIO_Mode = GPIO_Mode_IN_FLOATING;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_Init(GPIOC, &GPIO_InitStructure);  

    //Usart4 NVIC ïŋ―ïŋ―ïŋ―ïŋ―
    NVIC_InitStructure.NVIC_IRQChannel = UART4_IRQn;
	NVIC_InitStructure.NVIC_IRQChannelPreemptionPriority= 2;//ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―Čžïŋ―3
	NVIC_InitStructure.NVIC_IRQChannelSubPriority = 2;		//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Čžïŋ―3
	NVIC_InitStructure.NVIC_IRQChannelCmd = ENABLE;			//IRQÍĻïŋ―ïŋ―Ęđïŋ―ïŋ―
	NVIC_Init(&NVIC_InitStructure);	        //ïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęžïŋ―ïŋ―VICïŋ―Äīïŋ―ïŋ―ïŋ―

    //USART4 ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	USART_InitStructure.USART_BaudRate = bound;   //Ōŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ9600;
	USART_InitStructure.USART_WordLength = USART_WordLength_8b;  //ïŋ―Öģïŋ―ÎŠ8Îŧïŋ―ïŋ―ïŋ―Ýļïŋ―Ę―
	USART_InitStructure.USART_StopBits = USART_StopBits_1;  //Ōŧïŋ―ïŋ―ÍĢÖđÎŧ
	USART_InitStructure.USART_Parity = USART_Parity_No;  //ïŋ―ïŋ―ïŋ―ïŋ―ÅžÐĢïŋ―ïŋ―Îŧ
	USART_InitStructure.USART_HardwareFlowControl = USART_HardwareFlowControl_None;  //ïŋ―ïŋ―Óēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	USART_InitStructure.USART_Mode = USART_Mode_Rx | USART_Mode_Tx;	  //ïŋ―Õ·ïŋ―ÄĢĘ―

    USART_Init(UART4, &USART_InitStructure);   //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    USART_ITConfig(UART4, USART_IT_RXNE, ENABLE);  //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
    USART_Cmd(UART4, ENABLE);                      //Ęđïŋ―Üīïŋ―ïŋ―ïŋ― 

//	USART_DMACmd(USART2,USART_DMAReq_Tx,ENABLE);    //Ęđïŋ―Üīïŋ―ïŋ―ïŋ―2ïŋ―ïŋ―DMAïŋ―ïŋ―ïŋ―ïŋ―
//	UART_DMA_Config(DMA1_Channel7,(u32)&USART2->DR,(u32)USART2_TX_BUF,1000);  //DMA1ÍĻïŋ―ïŋ―7,ïŋ―ïŋ―ïŋ―ïŋ―ÎŠïŋ―ïŋ―ïŋ―ïŋ―2,ïŋ―æīĒïŋ―ïŋ―ÎŠUSART2_TX_BUF,ïŋ―ïŋ―ïŋ―ïŋ―1000. 										  	
}



void ModBus_Uart4_Local_Communication(void)
{
	/**************ïŋ―Öŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―***********************/	
		uint8  i = 0;	

		uint16 checksum = 0;

		if(Sys_Admin.Device_Style == 0 || Sys_Admin.Device_Style == 1) //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Íŧïŋ―ïŋ―Æīïŋ―ïŋ―ïŋ―ÍĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ę§ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
			{
				if(sys_flag.Address_Number >= 1)
					{
						if(sys_flag.UnTalk_Time >= 20) //15ïŋ―ïŋ―
							{
								 //ïŋ―čąļïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŨīĖŽ

								if(LCD4013X.DLCD.UnionControl_Flag)
									{
										LCD4013X.DLCD.UnionControl_Flag = 0; 
										if(sys_data.Data_10H == 2)
											{
												 sys_flag.Find_Flag = 99; //**********************ïŋ―ïŋ―ïŋ―ïŋ―Ęđïŋ―ïŋ―
												sys_close_cmd();

											}
									}

								if(sys_data.Data_10H == 3)
									{
										//ïŋ―ïŋ―ïŋ―Ãŧïŋ―Ð·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
										 if(sys_flag.Lcd4013_OnLive_Flag == 0)
										 	{
										 		 sys_data.Data_10H = 0;
										 		 GetOut_Mannual_Function();
										 	}

									}
							}

					}
			}






		if(U4_Inf.Recive_Ok_Flag)
			{
				U4_Inf.Recive_Ok_Flag = 0;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Åķ
				 //ïŋ―Øąïŋ―ïŋ―Ðķïŋ―
				USART_ITConfig(UART4, USART_IT_RXNE, DISABLE); 

				checksum  = U4_Inf.RX_Data[U4_Inf.RX_Length - 2] * 256 + U4_Inf.RX_Data[U4_Inf.RX_Length - 1];





			//ïŋ―Ï°ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―čąļïŋ―ïŋ―ïŋ―ÐšÅ―ïŋ―ïŋ―ïŋ―ïŋ―Þļïŋ―
				if( checksum == ModBusCRC16(U4_Inf.RX_Data,U4_Inf.RX_Length))
					{
						//u4_printf("\n*ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―= %d\n",Sys_Admin.ModBus_Address);

						if(sys_flag.Address_Number == 0)
							{
								//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äŧïŋ―čķĻïŋ―ïŋ―Ö·
								//if(U4_Inf.RX_Data[0] ==Sys_Admin.ModBus_Address)
								//	UART4_Server_Cmd_Analyse();
							}
						else
							{
								//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―åēĶïŋ―ïŋ―ïŋ―Ö·
								if(U4_Inf.RX_Data[0] == sys_flag.Address_Number)
									{
										sys_flag.UnTalk_Time = 0;
										LCD4013X.DLCD.UnionControl_Flag = OK;  //ïŋ―čąļïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŨīĖŽ
										UART4_Server_Cmd_Analyse();
									}

							}



					}



			//ïŋ―Ô―ïŋ―ïŋ―Õŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
				for( i = 0; i < 200;i++ )
					U4_Inf.RX_Data[i] = 0x00;

			//ïŋ―ïŋ―ïŋ―Âŋïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
				USART_ITConfig(UART4, USART_IT_RXNE, ENABLE); 

			}
}



