void uart3_init(u32 bound)
{  	 		 
	//GPIOïŋ―Ëŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_InitTypeDef GPIO_InitStructure;
	USART_InitTypeDef USART_InitStructure;
	NVIC_InitTypeDef NVIC_InitStructure;

	RCC_APB1PeriphClockCmd(RCC_APB1Periph_USART3, ENABLE);	//Ęđïŋ―ïŋ―USART3
	RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOB, ENABLE);	//Ęđïŋ―ïŋ―GPIOBĘąïŋ―ïŋ―
	USART_DeInit(USART3);  //ïŋ―ïŋ―Îŧïŋ―ïŋ―ïŋ―ïŋ―3

     //USART3_TX   PB.10
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_10; //PB.10
    GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
