uint8 Alarm_Out_Function(void)
{
	uint8 Alarm_Flag = 0;
	uint8 Address = 0;


	for(Address = 1; Address <= 10; Address ++)
		{
			if(JiZu[Address].Slave_D.Error_Code)
				{
					Alarm_Flag = OK;
				}
		}

	if(UnionLCD.UnionD.Union_Error)
		{
			Alarm_Flag = OK;

		}



	if( Alarm_Flag )
		{
			if(AUnionD.Alarm_OFF)
				{
					//ïŋ―Ðąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
					RELAY1_OFF;
				}
			else
				{
					RELAY1_ON;
				}


		}
	else
		{
			//ïŋ―ïŋ―Ãŧïŋ―Ðđïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ČĄïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öūïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÂīÎąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
			AUnionD.Alarm_OFF = 0;
			RELAY1_OFF;
		}




	return 0;
}

uint8 Relays_NoInterrupt_ON_OFF(void)
{
	if(sys_flag.Interrupt_Alive == FALSE)
		{
			if(Switch_Inf.air_on_flag)
	  		 	{
	  		 		RELAY6_ON;  //ïŋ―Í·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―

	  		 	}
			 else
			 	{
			 		RELAY6_OFF;  //ïŋ―Í·ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―

			 	}

			 if(Switch_Inf.gas_on_flag)
			 	{
			 		RELAY7_ON;
			 	}
			 else
			 	{
			 		RELAY7_OFF;
			 	}

			 if(Switch_Inf.dian_huo_flag)
			 	{
			 		RELAY8_ON;
			 	}
			 else
			 	{
			 		RELAY8_OFF;
			 	}


			 if(Switch_Inf.water_switch_flag)
			 	{
			 		RELAY5_ON;
			 	}
			 else
			 	{
			 		RELAY5_OFF;
			 	}

			 if(Switch_Inf.Water_Valve_Flag)
			 	{
			 		RELAY4_ON;
			 	}
			 else
			 	{
			 		RELAY4_OFF;
			 	}

			 if(Switch_Inf.pai_wu_flag)
			 	{
			 		RELAY9_ON;
			 	}
			 else
			 	{
			 		RELAY9_OFF;
			 	}

			 if(Switch_Inf.MingHuo_Flag)
			 	{
			 		RELAY2_ON;
			 	}
			 else
			 	{
			 		RELAY2_OFF;
			 	}

			  if(Switch_Inf.LianXu_PaiWu_flag)
			 	{
			 		RELAY10_ON;
			 	}
			 else
			 	{
			 		RELAY10_OFF;
			 	}


		}


	return 0;
}

