	NVIC_InitStructure.NVIC_IRQChannelCmd = ENABLE; //IRQÍĻïŋ―ïŋ―ïŋ―ïŋ―Ęđïŋ―ïŋ―
	NVIC_Init(&NVIC_InitStructure);  //ïŋ―ïŋ―Ęžïŋ―ïŋ―NVICïŋ―Äīïŋ―ïŋ―ïŋ―

	TIM_Cmd(TIM5, DISABLE);  //Ęđïŋ―ïŋ―TIMx					 
