 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―Úēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
 */
static void TIM3_GPIO_Config(void) 
{
  GPIO_InitTypeDef GPIO_InitStructure;	 
  RCC_APB1PeriphClockCmd(RCC_APB1Periph_TIM3, ENABLE); 	/* TIM3Ęąïŋ―ïŋ―Ęđïŋ―ïŋ― */
  RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOB, ENABLE); /* GPIOB Ęąïŋ―ïŋ―Ęđïŋ―ïŋ― */

  GPIO_InitStructure.GPIO_Pin =  GPIO_Pin_1 ;
  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AF_PP;		    //  PB1 ïŋ―ïŋ―ÎŠPWMĘđïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
  GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
  GPIO_Init(GPIOB, &GPIO_InitStructure);


}

/*
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―TIM3_Mode_Config
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―TIM3ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―PWMïŋ―ÅšÅĩïŋ―ÄĢĘ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÚĄïŋ―ïŋ―ïŋ―ïŋ―ÔĄïŋ―Õžïŋ―Õąïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―ïŋ―
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―ïŋ―Úēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
 */
static void TIM3_Mode_Config(void)
{
	TIM_TimeBaseInitTypeDef  TIM_TimeBaseStructure;
	TIM_OCInitTypeDef  TIM_OCInitStructure;

	/* PWMïŋ―ÅšÅĩïŋ―Æ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ */


/* -----------------------------------------------------------------------
		ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Âđïŋ―Ę―ïŋ―ïŋ―ïŋ―ïŋ―
    Frequency= TIMxCLK/( TIM_Prescaler +1)/ (TIM_Period + 1)
    TIMx Channelx duty cycle = (TIMx_Pulse/ ( TIM_Prescaler +1))* 100%
    TIM3CLK = 72 MHz, Prescaler = 0x0, TIM3 counter clock = TIM3CLK/(Prescaler+1)=72M
    TIM3 ARR Register = 999 => TIM3 Frequency = TIM3 counter clock/(ARR + 1)
    TIM3 Frequency = 72 KHz.
    TIM3 Channel1 duty cycle = 50%

  ----------------------------------------------------------------------- */

  /* Time base configuration */		 
  TIM_TimeBaseStructure.TIM_Period = 500;       //ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―0ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―999ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ1000ïŋ―ÎĢïŋ―ÎŠŌŧïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―
  TIM_TimeBaseStructure.TIM_Prescaler = 71;	    //ïŋ―ïŋ―ïŋ―ïŋ―ÔĪïŋ―ïŋ―Æĩïŋ―ïŋ―ïŋ―ïŋ―ÔĪïŋ―ïŋ―Æĩïŋ―ïŋ―ïŋ―ïŋ―ÎŠ72MHz
  TIM_TimeBaseStructure.TIM_ClockDivision = TIM_CKD_DIV1 ;	//ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―Ó·ïŋ―ÆĩÏĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Æĩ
  TIM_TimeBaseStructure.TIM_CounterMode = TIM_CounterMode_Up;  //ïŋ―ïŋ―ïŋ―Ïžïŋ―ïŋ―ïŋ―ÄĢĘ―
  TIM_TimeBaseInit(TIM3, &TIM_TimeBaseStructure);

  /* PWM1 Mode configuration: Channel1 */
  TIM_OCInitStructure.TIM_OCMode = TIM_OCMode_PWM1;	    //ïŋ―ïŋ―ïŋ―ïŋ―ÎŠPWMÄĢĘ―1
  TIM_OCInitStructure.TIM_OutputState = TIM_OutputState_Enable;	

  TIM_OCInitStructure.TIM_Pulse = CCR1_Val;	   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÖĩĘąïŋ―ïŋ―ïŋ―ïŋ―Æ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
  TIM_OCInitStructure.TIM_OCPolarity = TIM_OCPolarity_High;  //ïŋ―ïŋ―ïŋ―ïŋ―Ęąïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÖĩÐĄïŋ―ïŋ―CCR1_ValĘąÎŠïŋ―ßĩïŋ―Æ―
  TIM_OC4Init(TIM3, &TIM_OCInitStructure);	 //Ęđïŋ―ïŋ―ÍĻïŋ―ïŋ―1
  TIM_OC4PreloadConfig(TIM3, TIM_OCPreload_Enable);


  TIM_ARRPreloadConfig(TIM3, ENABLE);			 // Ęđïŋ―ïŋ―TIM3ïŋ―ïŋ―ïŋ―ØžÄīïŋ―ïŋ―ïŋ―ARR

  /* TIM3 enable counter */
  TIM_Cmd(TIM3, ENABLE);                   //Ęđïŋ―Üķïŋ―Ęąïŋ―ïŋ―3	
}

/*
 * ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―TIM5_PWM_Init
 * ïŋ―ïŋ―ïŋ―ïŋ―  ïŋ―ïŋ―TIM5 ïŋ―ïŋ―ïŋ―PWMïŋ―ÅšÅģïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ÖŧŌŠïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
 *         TIM5ïŋ―ïŋ―ïŋ―Äļïŋ―ÍĻïŋ―ïŋ―ïŋ―Íŧïŋ―ïŋ―ïŋ―PWMïŋ―Åšïŋ―ïŋ―ïŋ―ïŋ―
