}



void PWM_Adjust(uint8 value)
{
	//ŨĒïŋ―ïŋ―ÍĻïŋ―ïŋ―4 CRRïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ŌŠïŋ―Äģïŋ―4
	if(value > 100)
		value = 100;

	TIM3->CCR4 = (Frequence_PWM + 1) - (5 * value);

	sys_data.Data_1FH = value;
	LCD10D.DLCD.Air_Power = value;
	now_percent =value;

	//PID.Old_Put = value *100;  //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩïŋ―ïŋ―Į°ïŋ―ïŋ―PID


