void U2_send_byte(u8 data)
{

	while(USART_GetFlagStatus(USART2,USART_FLAG_TC)!=SET);
		USART_SendData(USART2,data);

}

//ïŋ―ïŋ―ïŋ―ïŋ―4ïŋ―ïŋ―ïŋ―ïŋ―sïŋ―ïŋ―ïŋ―Ö·ïŋ―
void U2_send_str(u8 *str,u8 s)
{
	u8 i;
	for(i=0;i<s;i++)
	{
		U2_send_byte(*str);
		str++;
	}
}


void u2_printf(char* fmt,...)  
{  
  	int len=0;
	int cnt=0;
	va_list ap;
	va_start(ap,fmt);
	vsprintf((char*)U2_Inf.TX_Data,fmt,ap);
	va_end(ap);
	len = strlen((const char*)U2_Inf.TX_Data);
	while(len--)
	  {
	  while(USART_GetFlagStatus(USART2,USART_FLAG_TC)!=1); //ïŋ―Čīïŋ―ïŋ―ïŋ―ïŋ―Í―ïŋ―ïŋ―ïŋ―
	  USART_SendData(USART2,U2_Inf.TX_Data[cnt++]);
	  }
}




