void uart2_init(u32 bound)
{  	 		 
	//GPIOïŋ―Ëŋïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_InitTypeDef GPIO_InitStructure;
	USART_InitTypeDef USART_InitStructure;
	NVIC_InitTypeDef NVIC_InitStructure;

	RCC_APB1PeriphClockCmd(RCC_APB1Periph_USART2, ENABLE);	//Ęđïŋ―ïŋ―USART2
	RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOA, ENABLE);	//Ęđïŋ―ïŋ―GPIOAĘąïŋ―ïŋ―
	USART_DeInit(USART2);  //ïŋ―ïŋ―Îŧïŋ―ïŋ―ïŋ―ïŋ―2

     //USART2_TX   PA.2
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_2; //PA.2
    GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
    GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AF_PP;	//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_Init(GPIOA, &GPIO_InitStructure);

    //USART2_RX	  PA.3
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_3;
    GPIO_InitStructure.GPIO_Mode = GPIO_Mode_IN_FLOATING;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    GPIO_Init(GPIOA, &GPIO_InitStructure);  

    //Usart2 NVIC ïŋ―ïŋ―ïŋ―ïŋ―
    NVIC_InitStructure.NVIC_IRQChannel = USART2_IRQn;
	NVIC_InitStructure.NVIC_IRQChannelPreemptionPriority= 2;//ïŋ―ïŋ―Õžïŋ―ïŋ―ïŋ―Čžïŋ―3
	NVIC_InitStructure.NVIC_IRQChannelSubPriority = 1;		//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Čžïŋ―3
	NVIC_InitStructure.NVIC_IRQChannelCmd = ENABLE;			//IRQÍĻïŋ―ïŋ―Ęđïŋ―ïŋ―
	NVIC_Init(&NVIC_InitStructure);	        //ïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―ïŋ―Äēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ęžïŋ―ïŋ―VICïŋ―Äīïŋ―ïŋ―ïŋ―

    //USART2 ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	USART_InitStructure.USART_BaudRate = bound;   //Ōŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÎŠ115200;
	USART_InitStructure.USART_WordLength = USART_WordLength_8b;  //ïŋ―Öģïŋ―ÎŠ8Îŧïŋ―ïŋ―ïŋ―Ýļïŋ―Ę―
	USART_InitStructure.USART_StopBits = USART_StopBits_1;  //Ōŧïŋ―ïŋ―ÍĢÖđÎŧ
	USART_InitStructure.USART_Parity = USART_Parity_No;  //ïŋ―ïŋ―ïŋ―ïŋ―ÅžÐĢïŋ―ïŋ―Îŧ
	USART_InitStructure.USART_HardwareFlowControl = USART_HardwareFlowControl_None;  //ïŋ―ïŋ―Óēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	USART_InitStructure.USART_Mode = USART_Mode_Rx | USART_Mode_Tx;	  //ïŋ―Õ·ïŋ―ÄĢĘ―

    USART_Init(USART2, &USART_InitStructure);   //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
    USART_ITConfig(USART2, USART_IT_RXNE, ENABLE);  //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðķïŋ―
    USART_Cmd(USART2, ENABLE);                      //Ęđïŋ―Üīïŋ―ïŋ―ïŋ― 

//	USART_DMACmd(USART2,USART_DMAReq_Tx,ENABLE);    //Ęđïŋ―Üīïŋ―ïŋ―ïŋ―2ïŋ―ïŋ―DMAïŋ―ïŋ―ïŋ―ïŋ―
//	UART_DMA_Config(DMA1_Channel7,(u32)&USART2->DR,(u32)USART2_TX_BUF,1000);  //DMA1ÍĻïŋ―ïŋ―7,ïŋ―ïŋ―ïŋ―ïŋ―ÎŠïŋ―ïŋ―ïŋ―ïŋ―2,ïŋ―æīĒïŋ―ïŋ―ÎŠUSART2_TX_BUF,ïŋ―ïŋ―ïŋ―ïŋ―1000. 										  	
}



void Union_ModBus2_Communication(void)
{

		uint8  i = 0;	
		uint8 index = 0;
		uint8 Bytes = 0;

		uint8 Modbus_Address = 0;

		uint16 checksum = 0;
		uint8  Cmd_Data = 0;
		uint16 Data_Address = 0;
		uint16 Buffer_Data16 = 0;
		uint16 Data_Length = 0;
		uint8  Index_Address = 0;

		uint16 Buffer_Int1 = 0;


		if(U2_Inf.Recive_Ok_Flag)
			{
				U2_Inf.Recive_Ok_Flag = 0;//ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Åķ
				 //ïŋ―Øąïŋ―ïŋ―Ðķïŋ―
				USART_ITConfig(USART2, USART_IT_RXNE, DISABLE); 

				checksum  = U2_Inf.RX_Data[U2_Inf.RX_Length - 2] * 256 + U2_Inf.RX_Data[U2_Inf.RX_Length - 1];


				if(checksum == ModBusCRC16(U2_Inf.RX_Data,U2_Inf.RX_Length))
					{	
						Modbus_Address = U2_Inf.RX_Data[0];
						Cmd_Data = U2_Inf.RX_Data[1];



						if(Cmd_Data == 0x03 && Modbus_Address == 1)
							{
								sys_flag.LCD10_Connect = OK;

								Data_Address = U2_Inf.RX_Data[2] * 256 + U2_Inf.RX_Data[3];
								Buffer_Data16 = U2_Inf.RX_Data[4] * 256 + U2_Inf.RX_Data[5];
								Data_Length = Buffer_Data16;
								switch (Data_Address)
									{
									 case 0x0000:


									 			Bytes = sizeof(UnionLCD.Datas);
												U2_Inf.TX_Data[0] = 0x01;
												U2_Inf.TX_Data[1]= 0x03;
									 			U2_Inf.TX_Data[2] = Bytes; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ČļÄąïŋ―


									 			for(index = 3; index < (Bytes + 3); index ++)
													U2_Inf.TX_Data[index] = UnionLCD.Datas[index -3];


									 			checksum  = ModBusCRC16(U2_Inf.TX_Data,Bytes + 5);
												U2_Inf.TX_Data[Bytes + 3] = checksum >> 8;
												U2_Inf.TX_Data[Bytes + 4] = checksum & 0x00FF;

									 			Usart_SendStr_length(USART2,U2_Inf.TX_Data,Bytes +5);


									 			break;

									case 0x0063://ČĄïŋ―ïŋ―ïŋ―ïŋ―1ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Bytes = sizeof(JiZu[1].Datas);
												U2_Inf.TX_Data[0] = 0x01;
												U2_Inf.TX_Data[1]= 0x03;
									 			U2_Inf.TX_Data[2] = Bytes; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýģïŋ―ïŋ―ČļÄąïŋ―


									 			for(index = 3; index < (Bytes + 3); index ++)
													U2_Inf.TX_Data[index] = JiZu[1].Datas[index -3]; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―

									 			checksum  = ModBusCRC16(U2_Inf.TX_Data,Bytes + 5);
												U2_Inf.TX_Data[Bytes + 3] = checksum >> 8;
												U2_Inf.TX_Data[Bytes + 4] = checksum & 0x00FF;

									 			Usart_SendStr_length(USART2,U2_Inf.TX_Data,Bytes +5);

												break;
									case 0x0077://ČĄïŋ―ïŋ―ïŋ―ïŋ―2ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(2);
												break;

									case 0x008B://ČĄïŋ―ïŋ―ïŋ―ïŋ―3ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(3);
												break;

									case 0x009F://ČĄïŋ―ïŋ―ïŋ―ïŋ―4ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(4);
												break;
									case 0x00B3://ČĄïŋ―ïŋ―ïŋ―ïŋ―5ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(5);
												break;
									case 0x00C7://ČĄïŋ―ïŋ―ïŋ―ïŋ―6ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(6);
												break;
									case 0x00DB://ČĄïŋ―ïŋ―ïŋ―ïŋ―7ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(7);
												break;
									case 0x00EF://ČĄïŋ―ïŋ―ïŋ―ïŋ―8ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(8);
												break;
									case 0x0103://ČĄïŋ―ïŋ―ïŋ―ïŋ―9ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(9);
												break;
									case 0x0117://ČĄïŋ―ïŋ―ïŋ―ïŋ―10ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öĩ
												Jizu_ReadResponse(10);
												break;
									default:


											break;
									}
							}

						if(Cmd_Data == 0x10 && Modbus_Address == 1)
							{
								 //01  10  00 A4	00 02  04  00 0F 3D DD 18 EE Ðī32Îŧïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―ïŋ―Ę―
					  			 //ïŋ―ïŋ―ÓĶïŋ―ïŋ― 01 10 00 A4	  00 02 crc
					  			 sys_flag.LCD10_Connect = OK;
								Data_Address = U2_Inf.RX_Data[2] * 256 + U2_Inf.RX_Data[3];
								Data_Length = U2_Inf.RX_Data[4] * 256 + U2_Inf.RX_Data[5];
								Buffer_Data16 = U2_Inf.RX_Data[7]  + U2_Inf.RX_Data[8] * 256;  //ïŋ―ßĩïŋ―ïŋ―Ö―Úĩïŋ―Ëģïŋ―ïŋ―ßĩïŋ―  //ïŋ―ßĩïŋ―ïŋ―Ö―Úĩïŋ―Ëģïŋ―ïŋ―ßĩïŋ―

								switch (Data_Address)
									{
									 case 0x0000:  //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öļïŋ―ïŋ―

													switch (Buffer_Data16)
														{
														case 0: //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
																if(AUnionD.UnionStartFlag == 1)  //ïŋ―čąļïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĢïŋ―ïŋ―ïŋ―Öīïŋ―ÐđØąïŋ―
																	{
																		AUnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.UnionStartFlag = Buffer_Data16;
																	}
																if(AUnionD.UnionStartFlag == 3)  //ïŋ―čąļïŋ―Öķïŋ―ÄĢĘ―ïŋ―ïŋ―ïŋ―ïŋ―Öīïŋ―ïŋ―ïŋ―Ëģïŋ―ïŋ―Öķïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ðīïŋ―ïŋ―ïŋ―
																	{
																		for(Index_Address = 1; Index_Address <= 10; Index_Address ++)
											 								{
											 									JiZu[Index_Address].Slave_D.StartFlag = 0; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ČŦïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÄĢĘ―
											 									JiZu[Index_Address].Slave_D.Realys_Out = 0;  //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐžĖĩïŋ―ïŋ―ïŋ―
											 									SlaveG[Index_Address].Out_Power = 0;
											 								}
																		AUnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.ZongKong_RelaysOut = 0;
																	}

																break;
														case 1:
																if(AUnionD.UnionStartFlag == 0)  //ïŋ―čąļïŋ―Úīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
																	{
																		AUnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.UnionStartFlag = Buffer_Data16;
																	}

																break;
														case 3:
																if(AUnionD.UnionStartFlag == 0)  //ïŋ―čąļïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÄĢĘ―ïŋ―ïŋ―ïŋ―ïŋ―Öīïŋ―Ð―ïŋ―ïŋ―ïŋ―ïŋ―Öķïŋ―ïŋ―ïŋ―
																	{
																		for(Index_Address = 1; Index_Address <= 10; Index_Address ++)
											 								{
											 									JiZu[Index_Address].Slave_D.StartFlag = 3; //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ČŦïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Öķïŋ―ÄĢĘ―
											 									JiZu[Index_Address].Slave_D.Realys_Out = 0;  //ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐžĖĩïŋ―ïŋ―ïŋ―
											 									SlaveG[Index_Address].Out_Power = 0;
											 								}
																		AUnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.UnionStartFlag = Buffer_Data16;
																		UnionLCD.UnionD.ZongKong_RelaysOut = 0;
																	}

																break;
														default:
																break;
														}

									 			  ModuBus2LCD_Write0x10Response(Data_Address,Data_Length);

									 			break;
									case 0x0001:  //ïŋ―ïŋ―ïŋ―ïŋ―Ęđïŋ―ïŋ―ĖĻïŋ―ïŋ―
												if(Buffer_Data16 <= 10)  //ïŋ―ïŋ―ïŋ―ÃĩÄēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĄïŋ―ïŋ―10
									 				UnionLCD.UnionD.Need_Numbers = Buffer_Data16;
												else
													Buffer_Data16 = UnionLCD.UnionD.Need_Numbers;

												AUnionD.Need_Numbers = UnionLCD.UnionD.Need_Numbers;


									 			ModuBus2LCD_Write0x10Response(Data_Address,Buffer_Data16);

									 			break;

									 			break;
									case 0x0005:  //PIDŨŠïŋ―ïŋ―Ęąïŋ―ïŋ―

												if(Buffer_Data16 <= 100 && Buffer_Data16 >= 5)  //ïŋ―ïŋ―ïŋ―ÃĩÄēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĄïŋ―ïŋ―100,ïŋ―ïŋ―ïŋ―ïŋ―5

