void SPI_Config_Init(void)
{
	uint8 i = 0;
  GPIO_InitTypeDef GPIO_InitStruct = {0};
	 RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOE, ENABLE);
  for(i=0;i<3;i++)
  {
		GPIO_InitStruct.GPIO_Pin = SPI_Gpio_Init.pin[i];
    GPIO_InitStruct.GPIO_Mode = GPIO_Mode_Out_PP;
    GPIO_InitStruct.GPIO_Speed = GPIO_Speed_50MHz;
		GPIO_Init(SPI_Gpio_Init.port[i], &GPIO_InitStruct);

  }
  for(i=3;i<4;i++)
  {
		GPIO_InitStruct.GPIO_Pin = SPI_Gpio_Init.pin[i];
    GPIO_InitStruct.GPIO_Mode = GPIO_Mode_IPU;
		GPIO_Init(SPI_Gpio_Init.port[i], &GPIO_InitStruct);
  }
  SPI_CS_H;
  SPI_CLK_L; 
}


void SpiCsStatus( uint8_t state)
{
  switch(state)
  {
	  case SPI_DISABLE:
			SPI_CS_H;
	  break;
	  case SPI_ENABLE:
			SPI_CS_L;
	  break;
  }
}
uint8 SPI_RW_Data_MODE0(uint8 sendData)
{
	uint8 n = 0;
	uint8 revData = 0;
	for(n=0;n<8;n++)
	{
		if(sendData&0x80)
			SPI_DIN_H;
		else 
			SPI_DIN_L;
		sendData <<= 1;
		SPI_delay_us(100);
		SPI_CLK_H;
		revData<<=1;
		if(SPI_MISO_DOUT)
			revData ++;
		SPI_delay_us(100);
		SPI_CLK_L;
	}
	return revData;
}


uint8  SpiReadData(void)
{
	uint8 ReciveData[5] = {0};
	uint8 DataCRC = 0;
	//uint8 TxData[5] = {0x68,0x00,0x64,0x01,0xCD};
	uint8 TxData[5] = {0};
	uint16 Alarm_Value = 0;
	static uint16 Alarm_Count = 0;

	static uint8 Unconnect_Count = 0;
	uint8  i=0;
	//ïŋ―ïŋ―ïŋ―ïŋ―: 0x68   (ïŋ―čķĻïŋ―ïŋ―ïŋ―Âķïŋ― HH LL)      (Ęđïŋ―ïŋ― 0x01)   (ïŋ―ïŋ―ÐĢïŋ―ïŋ―ČĄïŋ―ïŋ―Îŧ)

	//ïŋ―ïŋ―ïŋ―ïŋ―: 0x68   (ĘĩĘąïŋ―Âķïŋ― HH LL)      (Ęđïŋ―ïŋ― 0x01)   (ïŋ―ïŋ―ÐĢïŋ―ïŋ―ČĄïŋ―ïŋ―Îŧ)
	if(sys_flag.SPI_ReadRX_Flag == FALSE) //Ãŋïŋ―ïŋ―ïŋ―ïŋ―Ōŧïŋ―ïŋ―
		return 0;

	sys_flag.SPI_ReadRX_Flag = FALSE;

	if(sys_flag.Address_Number == 0)  //ïŋ―ÜŋØēïŋ―ïŋ―ïŋ―éąūïŋ―ïŋ―ïŋ―ïŋ―Âķïŋ―
		{
			Sys_Admin.YuRe_Enabled = 0; //ïŋ―ÜŋØēïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÂķČąïŋ―ïŋ―ïŋ―
		}

/******************ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ũžïŋ―ïŋ―ïŋ―Ũķïŋ―*******************/
	TxData[0] = 0x68; //ïŋ―Ėķïŋ―Í·
