static void ADCx_GPIO_Config(void)
{
	GPIO_InitTypeDef GPIO_InitStructure;

//================ïŋ―ïŋ―Â·4-20mAïŋ―ïŋ―ïŋ― PA0 ,PA1===============================================//

	// ïŋ―ïŋ― ADC IOïŋ―Ëŋïŋ―Ęąïŋ―ïŋ―
	ADC_GPIO_APBxClock_FUN ( ADC_GPIO_CLK, ENABLE );

	// ïŋ―ïŋ―ïŋ―ïŋ― ADC IO ïŋ―ïŋ―ïŋ―ïŋ―ÄĢĘ―
	GPIO_InitStructure.GPIO_Pin = 	ADC_PIN1 | ADC_PIN2;
	GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AIN;

	// ïŋ―ïŋ―Ęžïŋ―ïŋ― ADC IO
	GPIO_Init(ADC_PORT, &GPIO_InitStructure);			

//================ïŋ―ïŋ―Â·4-20mAïŋ―ïŋ―ïŋ― PC4ïŋ―ïŋ―PC5===============================================//
	// ïŋ―ïŋ― ADC IOïŋ―Ëŋïŋ―Ęąïŋ―ïŋ―
		/*ïŋ―ïŋ―ïŋ―ïŋ―PC0 ïŋ―ïŋ― PC1  ïŋ―ïŋ―ïŋ―Úžïŋ―ïŋ―ADSïŋ―ïŋ―Ãŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ßĩïŋ―*/
  RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOC, ENABLE);
  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AIN;  
  GPIO_InitStructure.GPIO_Pin  = GPIO_Pin_0 | GPIO_Pin_1;
  GPIO_Init(GPIOC, &GPIO_InitStructure); 





}

/**
  * @brief  ïŋ―ïŋ―ïŋ―ïŋ―ADCïŋ―ïŋ―ïŋ―ïŋ―ÄĢĘ―
  * @param  ïŋ―ïŋ―
  * @retval ïŋ―ïŋ―
  */
static void ADCx_Mode_Config(void)
{
	DMA_InitTypeDef DMA_InitStructure;
	ADC_InitTypeDef ADC_InitStructure;

	// ïŋ―ïŋ―DMAĘąïŋ―ïŋ―
	RCC_AHBPeriphClockCmd(ADC_DMA_CLK, ENABLE);
	// ïŋ―ïŋ―ADCĘąïŋ―ïŋ―
	ADC_APBxClock_FUN ( ADC_CLK, ENABLE );

	// ïŋ―ïŋ―ÎŧDMAïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	DMA_DeInit(ADC_DMA_CHANNEL);

	// ïŋ―ïŋ―ïŋ―ïŋ― DMA ïŋ―ïŋ―Ęžïŋ―ïŋ―ïŋ―áđđïŋ―ïŋ―
	// ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ÎŠïŋ―ïŋ―ADC ïŋ―ïŋ―ïŋ―ÝžÄīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·
	DMA_InitStructure.DMA_PeripheralBaseAddr = ( u32 ) ( & ( ADC_x->DR ) );

	// ïŋ―æīĒïŋ―ïŋ―ïŋ―ïŋ―Ö·
	DMA_InitStructure.DMA_MemoryBaseAddr = (u32)ADC_ConvertedValue;

	// ïŋ―ïŋ―ïŋ―ïŋ―Ôīïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
	DMA_InitStructure.DMA_DIR = DMA_DIR_PeripheralSRC;

	// ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÐĄïŋ―ïŋ―ÓĶïŋ―Ãĩïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Äŋïŋ―ÄĩØĩÄīïŋ―ÐĄ
	DMA_InitStructure.DMA_BufferSize = N*M;

	// ïŋ―ïŋ―ïŋ―ïŋ―Äīïŋ―ïŋ―ïŋ―Öŧïŋ―ïŋ―Ōŧïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―Ãĩïŋ―ïŋ―ïŋ―
	DMA_InitStructure.DMA_PeripheralInc = DMA_PeripheralInc_Disable;

	// ïŋ―æīĒïŋ―ïŋ―ïŋ―ïŋ―Ö·ïŋ―ïŋ―ïŋ―ïŋ―
	DMA_InitStructure.DMA_MemoryInc = DMA_MemoryInc_Enable; 

	// ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýīïŋ―ÐĄÎŠïŋ―ïŋ―ïŋ―ÖĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ö―ïŋ―
	DMA_InitStructure.DMA_PeripheralDataSize = DMA_PeripheralDataSize_HalfWord;

	// ïŋ―Úīïŋ―ïŋ―ïŋ―ïŋ―Ýīïŋ―ÐĄŌēÎŠïŋ―ïŋ―ïŋ―ÖĢïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―Ýīïŋ―ÐĄïŋ―ïŋ―ÍŽ
	DMA_InitStructure.DMA_MemoryDataSize = DMA_MemoryDataSize_HalfWord;

	// Ņ­ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ÄĢĘ―
	DMA_InitStructure.DMA_Mode = DMA_Mode_Circular;	

