/**
  * @brief ADS1220Init(void) ads1220ïŋ―ïŋ―Ęžïŋ―ïŋ―
  * @param none
  * @retval none
  */
void ADS1220Init(void)
{
	uint8_t i = 0;
  GPIO_InitTypeDef GPIO_InitStructure;
  RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOE, ENABLE);
  for(i=0;i<3;i++)
  {
	  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_Out_PP;   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―
      GPIO_InitStructure.GPIO_Speed = GPIO_Speed_10MHz;		
	  GPIO_InitStructure.GPIO_Pin = ADS1220_Init.pin[i]; 
	  GPIO_Init(GPIOE, &GPIO_InitStructure);
  }
  for(i=3;i<5;i++)
  {
	  GPIO_InitStructure.GPIO_Mode = GPIO_Mode_IPU;   //ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―ïŋ―	
	  GPIO_InitStructure.GPIO_Pin = ADS1220_Init.pin[i]; 
	  GPIO_Init(GPIOE, &GPIO_InitStructure);
  }
  ADS1220_CS_H;
  ADS1220_CLK_L;  
  return;
}
/**
  * @brief ADS1220Init(void) ads1220ïŋ―ïŋ―Ęžïŋ―ïŋ―
  * @param none
  * @retval none
  */
void ADS1220Config(void)
{
	  unsigned Temp;
	  /* AIN1 P AIN0 N ïŋ―Åīïŋ―ïŋ―ïŋ―8*/
    Temp = ADS1220_MUX_1_0 | ADS1220_GAIN_16 ;
    ADS1220WriteRegister(ADS1220_0_REGISTER, 0x01, &Temp);
    /*ïŋ―ïŋ―ïŋ―ïŋ―ŨŠïŋ―ïŋ―*/
    Temp = ADS1220_CC ;
    ADS1220WriteRegister(ADS1220_1_REGISTER, 0x01, &Temp);

    /*Ęđïŋ―ïŋ―ŨĻïŋ―ïŋ― REFP0 ïŋ―ïŋ― REFN0 ïŋ―ïŋ―ïŋ―ïŋ―ŅĄïŋ―ïŋ―ïŋ―ïŋ―âēŋïŋ―ïŋ―Ũžïŋ―ïŋ―Ņđ ÍŽĘąïŋ―ïŋ―ïŋ―ïŋ― 50Hz ïŋ―ïŋ― 60Hz 500ua*/
    Temp = ADS1220_IDAC_500 | 0x50 ;
	  ADS1220WriteRegister(ADS1220_2_REGISTER, 0x01, &Temp);

    Temp = ADS1220_IDAC1_AIN2 | ADS1220_IDAC2_AIN3  ;
	  ADS1220WriteRegister(ADS1220_3_REGISTER, 0x01, &Temp);

}

/**
  * @brief  Delay_us(uint16_t Value) 1us
  * @param ïŋ―ïŋ―Ęąusïŋ―ïŋ―ïŋ―ïŋ―
  * @retval int
  */
static void Delay_us(uint16_t Value)
{
	uint8_t i=0;
  while(Value--)
	{ 
		for(i=0;i<20;i++)
		{
			 __NOP;
		}
	}
}
/**
  * @brief int ADS1220WaitForDataReady(int Timeout)ïŋ―ïŋ―Ęžïŋ―ïŋ―
  * @param none
  * @retval none
  */
int ADS1220WaitForDataReady(int Timeout)
{

   return ADS1220_NO_ERROR;
}
/**
  * @brief  ADS1220CsStatus(uint8_t state);
  * @param state :ADS1220_DISABLE / ADS1220_ENABLE
  * @retval none
  */
void ADS1220CsStatus( uint8_t state)
{
  switch(state)
  {
	  case ADS1220_DISABLE:
		ADS1220_CS_H;
	  break;
	  case ADS1220_ENABLE:
		ADS1220_CS_L;
	  break;
  }
}


