  */
void SPI_Send_Data(uint8_t sendData)
{
	uint8_t n =0 ;
	for(n=0;n<8;n++)
	{
		ADS1220_CLK_L;
		Delay_us(20);
		if(sendData & 0x80)
			ADS1220_DIN_H;
		else 
			ADS1220_DIN_L;
		Delay_us(20);
		sendData <<= 1 ;
		ADS1220_CLK_H;
		Delay_us(20);
	}
	ADS1220_CLK_L;
}

/**
  * @brief  uint8_t SPI_Receiver_Data(void)
  * @param  none
  * @retval ïŋ―ïŋ―ïŋ―ïŋ―8Îŧïŋ―ïŋ―ïŋ―ïŋ―
  */
uint8_t SPI_Receiver_Data(void)
{
	uint8_t n = 0;
	uint8_t revData = 0;
	for(n=0;n<8;n++)
	{
		ADS1220_CLK_L;
		Delay_us(20);
		revData <<=1;
		if(ADS1200_DOUT)
			revData |= 0x01;
		else 
			revData &= 0xfe;
		Delay_us(20);
		ADS1220_CLK_H;
		Delay_us(20);
	}
	ADS1220_CLK_L;
	return revData;
}
